#Requires -Version 5.1

<#
.SYNOPSIS
    WinPE Builder Suite - Core Configuration Module
.DESCRIPTION
    Provides configuration management for the WinPE Builder suite.
    Handles loading, saving, and validating configuration settings.
.NOTES
    Module: WinPE.Core.Configuration
    Version: 1.0.0
#>

using namespace System.Collections.Generic

#region Module Variables
$script:Configuration = $null
$script:ConfigPath = $null
$script:DefaultSettings = $null
#endregion

#region Private Functions
function Resolve-ConfigurationPath {
    <#
    .SYNOPSIS
        Resolves variable placeholders in configuration paths.
    #>
    [CmdletBinding()]
    [OutputType([string])]
    param(
        [Parameter(Mandatory)]
        [string]$Path,

        [Parameter()]
        [string]$ModuleRoot
    )

    $resolved = $Path

    # Replace environment variables
    $resolved = $resolved -replace '\$\{env:([^}]+)\}', { 
        $envVar = $_.Groups[1].Value
        [Environment]::GetEnvironmentVariable($envVar)
    }

    # Replace ${ModuleRoot}
    if ($ModuleRoot) {
        $resolved = $resolved -replace '\$\{ModuleRoot\}', $ModuleRoot
    }

    return $resolved
}

function Merge-Configuration {
    <#
    .SYNOPSIS
        Merges two configuration objects, with override taking precedence.
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory)]
        [PSCustomObject]$Base,

        [Parameter(Mandatory)]
        [PSCustomObject]$Override
    )

    $result = $Base.PSObject.Copy()

    foreach ($property in $Override.PSObject.Properties) {
        if ($null -eq $property.Value) {
            continue
        }

        if ($property.Value -is [PSCustomObject] -and 
            $result.PSObject.Properties[$property.Name] -and
            $result.PSObject.Properties[$property.Name].Value -is [PSCustomObject]) {

            $result.PSObject.Properties[$property.Name].Value = Merge-Configuration `
                -Base $result.PSObject.Properties[$property.Name].Value `
                -Override $property.Value
        }
        else {
            if ($result.PSObject.Properties[$property.Name]) {
                $result.PSObject.Properties[$property.Name].Value = $property.Value
            }
            else {
                $result | Add-Member -NotePropertyName $property.Name -NotePropertyValue $property.Value
            }
        }
    }

    return $result
}

function Test-ConfigurationSchema {
    <#
    .SYNOPSIS
        Validates configuration against expected schema.
    #>
    [CmdletBinding()]
    [OutputType([bool])]
    param(
        [Parameter(Mandatory)]
        [PSCustomObject]$Config
    )

    $requiredSections = @(
        'environment',
        'paths',
        'build',
        'wimSettings',
        'bootMedia',
        'drivers',
        'components',
        'shell',
        'gui',
        'tools',
        'recovery',
        'capture',
        'network',
        'security',
        'logging'
    )

    foreach ($section in $requiredSections) {
        if (-not $Config.PSObject.Properties[$section]) {
            Write-Warning -Message "Missing required configuration section: $section"
            return $false
        }
    }

    return $true
}
#endregion

#region Public Functions
function Initialize-WinPEConfiguration {
    <#
    .SYNOPSIS
        Initializes the configuration system.
    .DESCRIPTION
        Loads configuration from the specified path or uses defaults.
    .PARAMETER ConfigPath
        Path to the configuration directory.
    .PARAMETER SettingsFile
        Name of the settings JSON file.
    .EXAMPLE
        Initialize-WinPEConfiguration -ConfigPath 'C:\WinPE-Builder\Config'
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [ValidateScript({ Test-Path -Path $_ -PathType Container })]
        [string]$ConfigPath,

        [Parameter()]
        [string]$SettingsFile = 'Settings.json'
    )

    $script:ConfigPath = $ConfigPath
    $settingsPath = Join-Path -Path $ConfigPath -ChildPath $SettingsFile

    if (Test-Path -Path $settingsPath -PathType Leaf) {
        try {
            $jsonContent = Get-Content -Path $settingsPath -Raw -Encoding UTF8
            $script:Configuration = $jsonContent | ConvertFrom-Json

            # Resolve paths
            $moduleRoot = Split-Path -Path $ConfigPath -Parent
            if ($script:Configuration.paths) {
                foreach ($prop in $script:Configuration.paths.PSObject.Properties) {
                    if ($prop.Value -is [string]) {
                        $prop.Value = Resolve-ConfigurationPath -Path $prop.Value -ModuleRoot $moduleRoot
                    }
                }
            }

            Write-Verbose -Message "Configuration loaded from: $settingsPath"
        }
        catch {
            throw "Failed to load configuration: $($_.Exception.Message)"
        }
    }
    else {
        throw "Configuration file not found: $settingsPath"
    }

    if (-not (Test-ConfigurationSchema -Config $script:Configuration)) {
        throw 'Configuration validation failed'
    }

    return $script:Configuration
}

function Get-WinPEConfiguration {
    <#
    .SYNOPSIS
        Retrieves the current configuration or a specific section.
    .DESCRIPTION
        Returns the full configuration object or a specific section by name.
    .PARAMETER Section
        Optional section name to retrieve.
    .PARAMETER Property
        Optional property path within a section (dot notation supported).
    .EXAMPLE
        Get-WinPEConfiguration
    .EXAMPLE
        Get-WinPEConfiguration -Section 'paths'
    .EXAMPLE
        Get-WinPEConfiguration -Section 'bootMedia' -Property 'usbPartitionScheme'
    #>
    [CmdletBinding()]
    param(
        [Parameter()]
        [string]$Section,

        [Parameter()]
        [string]$Property
    )

    if ($null -eq $script:Configuration) {
        throw 'Configuration not initialized. Call Initialize-WinPEConfiguration first.'
    }

    if ([string]::IsNullOrEmpty($Section)) {
        return $script:Configuration
    }

    if (-not $script:Configuration.PSObject.Properties[$Section]) {
        throw "Configuration section not found: $Section"
    }

    $sectionData = $script:Configuration.$Section

    if ([string]::IsNullOrEmpty($Property)) {
        return $sectionData
    }

    # Support dot notation for nested properties
    $parts = $Property -split '\.'
    $current = $sectionData

    foreach ($part in $parts) {
        if ($null -eq $current -or -not $current.PSObject.Properties[$part]) {
            return $null
        }
        $current = $current.$part
    }

    return $current
}

function Set-WinPEConfiguration {
    <#
    .SYNOPSIS
        Sets a configuration value.
    .DESCRIPTION
        Updates a configuration property with a new value.
    .PARAMETER Section
        The configuration section to update.
    .PARAMETER Property
        The property path within the section (dot notation supported).
    .PARAMETER Value
        The new value to set.
    .PARAMETER Save
        Save the configuration to disk after updating.
    .EXAMPLE
        Set-WinPEConfiguration -Section 'build' -Property 'compressionLevel' -Value 'Maximum'
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$Section,

        [Parameter(Mandatory)]
        [string]$Property,

        [Parameter(Mandatory)]
        [object]$Value,

        [Parameter()]
        [switch]$Save
    )

    if ($null -eq $script:Configuration) {
        throw 'Configuration not initialized. Call Initialize-WinPEConfiguration first.'
    }

    if (-not $script:Configuration.PSObject.Properties[$Section]) {
        throw "Configuration section not found: $Section"
    }

    $parts = $Property -split '\.'
    $current = $script:Configuration.$Section

    for ($i = 0; $i -lt $parts.Count - 1; $i++) {
        $part = $parts[$i]
        if (-not $current.PSObject.Properties[$part]) {
            $current | Add-Member -NotePropertyName $part -NotePropertyValue ([PSCustomObject]@{})
        }
        $current = $current.$part
    }

    $finalProperty = $parts[-1]
    if ($current.PSObject.Properties[$finalProperty]) {
        $current.PSObject.Properties[$finalProperty].Value = $Value
    }
    else {
        $current | Add-Member -NotePropertyName $finalProperty -NotePropertyValue $Value
    }

    if ($Save) {
        Save-WinPEConfiguration
    }
}

function Save-WinPEConfiguration {
    <#
    .SYNOPSIS
        Saves the current configuration to disk.
    .DESCRIPTION
        Writes the configuration object back to the settings JSON file.
    .PARAMETER Path
        Optional alternative path to save to.
    .EXAMPLE
        Save-WinPEConfiguration
    #>
    [CmdletBinding()]
    param(
        [Parameter()]
        [string]$Path
    )

    if ($null -eq $script:Configuration) {
        throw 'Configuration not initialized.'
    }

    $savePath = if ($Path) {
        $Path
    }
    else {
        Join-Path -Path $script:ConfigPath -ChildPath 'Settings.json'
    }

    try {
        $jsonContent = $script:Configuration | ConvertTo-Json -Depth 20
        $jsonContent | Out-File -FilePath $savePath -Encoding UTF8 -Force
        Write-Verbose -Message "Configuration saved to: $savePath"
    }
    catch {
        throw "Failed to save configuration: $($_.Exception.Message)"
    }
}

function Import-WinPEConfiguration {
    <#
    .SYNOPSIS
        Imports configuration from a JSON file.
    .DESCRIPTION
        Loads a configuration file and optionally merges with current settings.
    .PARAMETER Path
        Path to the JSON configuration file.
    .PARAMETER Merge
        Merge with current configuration instead of replacing.
    .EXAMPLE
        Import-WinPEConfiguration -Path 'C:\MyConfig.json' -Merge
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [ValidateScript({ Test-Path -Path $_ -PathType Leaf })]
        [string]$Path,

        [Parameter()]
        [switch]$Merge
    )

    try {
        $jsonContent = Get-Content -Path $Path -Raw -Encoding UTF8
        $importedConfig = $jsonContent | ConvertFrom-Json

        if ($Merge -and $null -ne $script:Configuration) {
            $script:Configuration = Merge-Configuration -Base $script:Configuration -Override $importedConfig
        }
        else {
            $script:Configuration = $importedConfig
        }

        Write-Verbose -Message "Configuration imported from: $Path"
        return $script:Configuration
    }
    catch {
        throw "Failed to import configuration: $($_.Exception.Message)"
    }
}

function Export-WinPEConfiguration {
    <#
    .SYNOPSIS
        Exports configuration to a JSON file.
    .DESCRIPTION
        Saves the current configuration to a specified file path.
    .PARAMETER Path
        Destination path for the JSON file.
    .PARAMETER Section
        Optional: Export only a specific section.
    .EXAMPLE
        Export-WinPEConfiguration -Path 'C:\Backup\Config.json'
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$Path,

        [Parameter()]
        [string]$Section
    )

    if ($null -eq $script:Configuration) {
        throw 'Configuration not initialized.'
    }

    $exportData = if ($Section) {
        if (-not $script:Configuration.PSObject.Properties[$Section]) {
            throw "Configuration section not found: $Section"
        }
        $script:Configuration.$Section
    }
    else {
        $script:Configuration
    }

    try {
        $directory = Split-Path -Path $Path -Parent
        if (-not (Test-Path -Path $directory -PathType Container)) {
            $null = New-Item -Path $directory -ItemType Directory -Force
        }

        $jsonContent = $exportData | ConvertTo-Json -Depth 20
        $jsonContent | Out-File -FilePath $Path -Encoding UTF8 -Force
        Write-Verbose -Message "Configuration exported to: $Path"
    }
    catch {
        throw "Failed to export configuration: $($_.Exception.Message)"
    }
}

function Get-WinPEToolsDefinition {
    <#
    .SYNOPSIS
        Retrieves tool definitions from the Tools.json configuration.
    .DESCRIPTION
        Returns all tool definitions or filtered by category/ID.
    .PARAMETER ToolId
        Optional tool ID to retrieve.
    .PARAMETER Category
        Optional category to filter by.
    .PARAMETER PortableOnly
        Return only portable tools.
    .PARAMETER FreeOnly
        Return only free tools.
    .EXAMPLE
        Get-WinPEToolsDefinition -Category 'diskImaging'
    #>
    [CmdletBinding()]
    param(
        [Parameter()]
        [string]$ToolId,

        [Parameter()]
        [string]$Category,

        [Parameter()]
        [switch]$PortableOnly,

        [Parameter()]
        [switch]$FreeOnly
    )

    $toolsPath = Join-Path -Path $script:ConfigPath -ChildPath 'Tools.json'

    if (-not (Test-Path -Path $toolsPath -PathType Leaf)) {
        throw "Tools definition file not found: $toolsPath"
    }

    $toolsContent = Get-Content -Path $toolsPath -Raw -Encoding UTF8 | ConvertFrom-Json
    $tools = $toolsContent.tools

    if ($ToolId) {
        return $tools | Where-Object { $_.id -eq $ToolId }
    }

    if ($Category) {
        $tools = $tools | Where-Object { $_.category -eq $Category }
    }

    if ($PortableOnly) {
        $tools = $tools | Where-Object { $_.portable -eq $true }
    }

    if ($FreeOnly) {
        $tools = $tools | Where-Object { $_.license -eq 'Free' }
    }

    return $tools
}

function Get-WinPEToolCategories {
    <#
    .SYNOPSIS
        Retrieves tool category definitions.
    .EXAMPLE
        Get-WinPEToolCategories
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param()

    $toolsPath = Join-Path -Path $script:ConfigPath -ChildPath 'Tools.json'

    if (-not (Test-Path -Path $toolsPath -PathType Leaf)) {
        throw "Tools definition file not found: $toolsPath"
    }

    $toolsContent = Get-Content -Path $toolsPath -Raw -Encoding UTF8 | ConvertFrom-Json
    return $toolsContent.categories
}

function Get-WinPEDriversConfiguration {
    <#
    .SYNOPSIS
        Retrieves driver configuration.
    .EXAMPLE
        Get-WinPEDriversConfiguration
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param()

    $driversPath = Join-Path -Path $script:ConfigPath -ChildPath 'Drivers.json'

    if (Test-Path -Path $driversPath -PathType Leaf) {
        return Get-Content -Path $driversPath -Raw -Encoding UTF8 | ConvertFrom-Json
    }

    # Return default from main config
    return Get-WinPEConfiguration -Section 'drivers'
}

function Test-WinPEConfigurationValid {
    <#
    .SYNOPSIS
        Validates the current configuration.
    .DESCRIPTION
        Performs comprehensive validation of configuration settings.
    .EXAMPLE
        Test-WinPEConfigurationValid
    #>
    [CmdletBinding()]
    [OutputType([bool])]
    param()

    if ($null -eq $script:Configuration) {
        Write-Warning -Message 'Configuration not initialized'
        return $false
    }

    $valid = $true
    $errors = [List[string]]::new()

    # Validate paths exist or can be created
    $pathsToValidate = @(
        'workingDirectory',
        'toolsCache',
        'driverStore',
        'isoOutput',
        'wimOutput',
        'logsDirectory'
    )

    foreach ($pathName in $pathsToValidate) {
        $pathValue = Get-WinPEConfiguration -Section 'paths' -Property $pathName
        if ([string]::IsNullOrEmpty($pathValue)) {
            $errors.Add("Path not configured: $pathName")
            $valid = $false
        }
    }

    # Validate ADK installation
    $adkPath = Get-WinPEConfiguration -Section 'paths' -Property 'adkRoot'
    if (-not (Test-Path -Path $adkPath -PathType Container)) {
        $errors.Add("Windows ADK not found at: $adkPath")
        $valid = $false
    }

    # Validate architecture
    $arch = Get-WinPEConfiguration -Section 'environment' -Property 'targetArchitecture'
    if ($arch -notin @('amd64', 'x86', 'arm64')) {
        $errors.Add("Invalid architecture: $arch")
        $valid = $false
    }

    if (-not $valid) {
        foreach ($error in $errors) {
            Write-Warning -Message "Configuration Error: $error"
        }
    }

    return $valid
}
#endregion

#region Module Exports
Export-ModuleMember -Function @(
    'Initialize-WinPEConfiguration',
    'Get-WinPEConfiguration',
    'Set-WinPEConfiguration',
    'Save-WinPEConfiguration',
    'Import-WinPEConfiguration',
    'Export-WinPEConfiguration',
    'Get-WinPEToolsDefinition',
    'Get-WinPEToolCategories',
    'Get-WinPEDriversConfiguration',
    'Test-WinPEConfigurationValid'
)
#endregion

{
