#Requires -Version 5.1
#Requires -RunAsAdministrator
<#
.SYNOPSIS
    WinPE-Builder-Suite Main Orchestrator Module
.DESCRIPTION
    Comprehensive WinPE/WinRE Custom Builder Suite providing GUI integration,
    tool management, driver injection, and deployment automation capabilities.
.NOTES
    Version: 1.0.0
    Author: WinPE-Builder-Suite
    Requires: Windows ADK, Administrator privileges
#>

using namespace System.IO
using namespace System.Collections.Generic

#region Module Variables
$script:WinPEBuilderRoot = $PSScriptRoot
$script:ConfigPath = Join-Path -Path $script:WinPEBuilderRoot -ChildPath 'Config'
$script:ModulesPath = Join-Path -Path $script:WinPEBuilderRoot -ChildPath 'Modules'
$script:ResourcesPath = Join-Path -Path $script:WinPEBuilderRoot -ChildPath 'Resources'
$script:OutputPath = Join-Path -Path $script:WinPEBuilderRoot -ChildPath 'Output'
$script:TempPath = Join-Path -Path $script:WinPEBuilderRoot -ChildPath 'Temp'
$script:LogPath = Join-Path -Path $script:WinPEBuilderRoot -ChildPath 'Logs'
$script:WinPEBuilderConfig = $null
$script:CurrentBuildSession = $null
#endregion

#region Logging Functions
function Write-WPELog {
    <#
    .SYNOPSIS
        Writes log messages to console and log file
    .PARAMETER Message
        The message to log
    .PARAMETER Level
        Log level: Information, Warning, Error, Debug, Verbose
    .PARAMETER NoConsole
        Suppress console output
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true, Position = 0)]
        [string]$Message,

        [Parameter(Position = 1)]
        [ValidateSet('Information', 'Warning', 'Error', 'Debug', 'Verbose')]
        [string]$Level = 'Information',

        [Parameter()]
        [switch]$NoConsole
    )

    $timestamp = Get-Date -Format 'yyyy-MM-dd HH:mm:ss.fff'
    $logEntry = "[$timestamp] [$Level] $Message"

    # Ensure log directory exists
    if (-not (Test-Path -Path $script:LogPath)) {
        New-Item -Path $script:LogPath -ItemType Directory -Force | Out-Null
    }

    $logFile = Join-Path -Path $script:LogPath -ChildPath "WinPE-Builder_$(Get-Date -Format 'yyyyMMdd').log"

    # Write to log file
    Add-Content -Path $logFile -Value $logEntry -Encoding UTF8

    # Write to console based on level
    if (-not $NoConsole) {
        switch ($Level) {
            'Information' { Write-Host $Message -ForegroundColor Cyan }
            'Warning' { Write-Warning $Message }
            'Error' { Write-Host $Message -ForegroundColor Red }
            'Debug' { Write-Debug $Message }
            'Verbose' { Write-Verbose $Message }
        }
    }
}

function Write-WPEProgress {
    <#
    .SYNOPSIS
        Displays progress information
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$Activity,

        [Parameter(Mandatory = $true)]
        [string]$Status,

        [Parameter()]
        [int]$PercentComplete = -1,

        [Parameter()]
        [int]$Id = 0,

        [Parameter()]
        [switch]$Completed
    )

    $progressParams = @{
        Activity = $Activity
        Status   = $Status
        Id       = $Id
    }

    if ($PercentComplete -ge 0) {
        $progressParams['PercentComplete'] = $PercentComplete
    }

    if ($Completed) {
        $progressParams['Completed'] = $true
    }

    Write-Progress @progressParams
    Write-WPELog -Message "$Activity - $Status" -Level 'Verbose' -NoConsole
}
#endregion

#region Configuration Functions
function Get-WinPEBuilderConfig {
    <#
    .SYNOPSIS
        Retrieves the WinPE Builder configuration
    .DESCRIPTION
        Loads and returns the build configuration from JSON file
    .PARAMETER ConfigPath
        Optional custom path to configuration file
    .EXAMPLE
        $config = Get-WinPEBuilderConfig
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param(
        [Parameter()]
        [ValidateScript({ Test-Path -Path $_ -PathType Leaf })]
        [string]$ConfigPath
    )

    begin {
        Write-WPELog -Message 'Loading WinPE Builder configuration' -Level 'Verbose'
    }

    process {
        try {
            if (-not $ConfigPath) {
                $ConfigPath = Join-Path -Path $script:ConfigPath -ChildPath 'BuildConfig.json'
            }

            if (-not (Test-Path -Path $ConfigPath)) {
                throw "Configuration file not found: $ConfigPath"
            }

            $configContent = Get-Content -Path $ConfigPath -Raw -Encoding UTF8
            $config = $configContent | ConvertFrom-Json

            # Cache the configuration
            $script:WinPEBuilderConfig = $config

            Write-WPELog -Message 'Configuration loaded successfully' -Level 'Information'
            return $config
        }
        catch {
            Write-WPELog -Message "Failed to load configuration: $_" -Level 'Error'
            throw
        }
    }
}

function Set-WinPEBuilderConfig {
    <#
    .SYNOPSIS
        Updates WinPE Builder configuration settings
    .DESCRIPTION
        Modifies and saves configuration settings to the JSON file
    .PARAMETER Setting
        The configuration path to update (e.g., 'build.outputPath')
    .PARAMETER Value
        The new value to set
    .PARAMETER ConfigPath
        Optional custom path to configuration file
    .EXAMPLE
        Set-WinPEBuilderConfig -Setting 'build.outputPath' -Value 'D:\WinPE\Output'
    #>
    [CmdletBinding(SupportsShouldProcess)]
    param(
        [Parameter(Mandatory = $true)]
        [string]$Setting,

        [Parameter(Mandatory = $true)]
        [object]$Value,

        [Parameter()]
        [string]$ConfigPath
    )

    begin {
        if (-not $ConfigPath) {
            $ConfigPath = Join-Path -Path $script:ConfigPath -ChildPath 'BuildConfig.json'
        }
    }

    process {
        try {
            $config = Get-WinPEBuilderConfig -ConfigPath $ConfigPath

            # Navigate to the setting using dot notation
            $parts = $Setting -split '\.'
            $current = $config

            for ($i = 0; $i -lt ($parts.Count - 1); $i++) {
                $current = $current.($parts[$i])
            }

            $propertyName = $parts[-1]

            if ($PSCmdlet.ShouldProcess($Setting, "Set value to '$Value'")) {
                $current.$propertyName = $Value

                # Save configuration
                $config | ConvertTo-Json -Depth 10 | Set-Content -Path $ConfigPath -Encoding UTF8

                # Update cached config
                $script:WinPEBuilderConfig = $config

                Write-WPELog -Message "Configuration '$Setting' updated to '$Value'" -Level 'Information'
            }
        }
        catch {
            Write-WPELog -Message "Failed to update configuration: $_" -Level 'Error'
            throw
        }
    }
}
#endregion

#region Prerequisites and Environment
function Test-WinPEBuilderPrerequisites {
    <#
    .SYNOPSIS
        Validates all prerequisites for WinPE Builder
    .DESCRIPTION
        Checks for Windows ADK, required permissions, and system requirements
    .PARAMETER Detailed
        Returns detailed information about each prerequisite
    .EXAMPLE
        Test-WinPEBuilderPrerequisites -Detailed
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param(
        [Parameter()]
        [switch]$Detailed
    )

    begin {
        Write-WPELog -Message 'Checking prerequisites...' -Level 'Information'
        $results = [List[PSCustomObject]]::new()
    }

    process {
        # Check Administrator privileges
        $isAdmin = ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
        $results.Add([PSCustomObject]@{
            Name        = 'Administrator Privileges'
            Status      = $isAdmin
            Required    = $true
            Description = 'Running with elevated privileges'
        })

        # Check Windows version
        $osVersion = [Environment]::OSVersion.Version
        $isWin10Plus = $osVersion.Major -ge 10
        $results.Add([PSCustomObject]@{
            Name        = 'Windows 10/11'
            Status      = $isWin10Plus
            Required    = $true
            Description = "Current: Windows $($osVersion.Major).$($osVersion.Minor)"
        })

        # Check Windows ADK
        $adkPaths = @(
            'C:\Program Files (x86)\Windows Kits\10\Assessment and Deployment Kit',
            "${env:ProgramFiles(x86)}\Windows Kits\10\Assessment and Deployment Kit"
        )

        $adkFound = $false
        $adkPath = $null
        foreach ($path in $adkPaths) {
            if (Test-Path -Path $path) {
                $adkFound = $true
                $adkPath = $path
                break
            }
        }

        $results.Add([PSCustomObject]@{
            Name        = 'Windows ADK'
            Status      = $adkFound
            Required    = $true
            Description = if ($adkFound) { "Found at: $adkPath" } else { 'Not found - Download from Microsoft' }
        })

        # Check WinPE add-on
        $winpePath = Join-Path -Path $adkPath -ChildPath 'Windows Preinstallation Environment'
        $winpeFound = Test-Path -Path $winpePath
        $results.Add([PSCustomObject]@{
            Name        = 'WinPE Add-on'
            Status      = $winpeFound
            Required    = $true
            Description = if ($winpeFound) { 'WinPE add-on installed' } else { 'Install WinPE add-on for ADK' }
        })

        # Check DISM
        $dismPath = Get-Command -Name 'dism.exe' -ErrorAction SilentlyContinue
        $results.Add([PSCustomObject]@{
            Name        = 'DISM'
            Status      = $null -ne $dismPath
            Required    = $true
            Description = if ($dismPath) { $dismPath.Source } else { 'DISM not found in PATH' }
        })

        # Check oscdimg (for ISO creation)
        $oscdimgPaths = @(
            (Join-Path -Path $adkPath -ChildPath 'Deployment Tools\amd64\Oscdimg\oscdimg.exe'),
            'C:\Program Files (x86)\Windows Kits\10\Assessment and Deployment Kit\Deployment Tools\amd64\Oscdimg\oscdimg.exe'
        )

        $oscdimgFound = $false
        foreach ($path in $oscdimgPaths) {
            if (Test-Path -Path $path) {
                $oscdimgFound = $true
                break
            }
        }

        $results.Add([PSCustomObject]@{
            Name        = 'oscdimg'
            Status      = $oscdimgFound
            Required    = $true
            Description = 'Required for ISO creation'
        })

        # Check free disk space (minimum 20GB recommended)
        $systemDrive = $env:SystemDrive
        $freeSpace = (Get-PSDrive -Name $systemDrive.TrimEnd(':')).Free / 1GB
        $hasEnoughSpace = $freeSpace -ge 20
        $results.Add([PSCustomObject]@{
            Name        = 'Disk Space'
            Status      = $hasEnoughSpace
            Required    = $true
            Description = "Free space: $([math]::Round($freeSpace, 2)) GB (20 GB minimum)"
        })

        # Check PowerShell version
        $psVersion = $PSVersionTable.PSVersion
        $isPsValid = $psVersion.Major -ge 5
        $results.Add([PSCustomObject]@{
            Name        = 'PowerShell Version'
            Status      = $isPsValid
            Required    = $true
            Description = "Current: PowerShell $($psVersion.Major).$($psVersion.Minor)"
        })

        # Check for Chocolatey (optional)
        $chocoPath = Get-Command -Name 'choco' -ErrorAction SilentlyContinue
        $results.Add([PSCustomObject]@{
            Name        = 'Chocolatey'
            Status      = $null -ne $chocoPath
            Required    = $false
            Description = if ($chocoPath) { 'Chocolatey available for tool downloads' } else { 'Optional: Install for automated tool downloads' }
        })

        # Check for winget (optional)
        $wingetPath = Get-Command -Name 'winget' -ErrorAction SilentlyContinue
        $results.Add([PSCustomObject]@{
            Name        = 'Winget'
            Status      = $null -ne $wingetPath
            Required    = $false
            Description = if ($wingetPath) { 'Winget available for tool downloads' } else { 'Optional: Install for automated tool downloads' }
        })

        # Summary
        $allRequired = $results | Where-Object { $_.Required -and -not $_.Status }
        $overallStatus = $allRequired.Count -eq 0

        if ($Detailed) {
            Write-Host "`n=== WinPE Builder Prerequisites ===" -ForegroundColor Yellow
            foreach ($result in $results) {
                $statusIcon = if ($result.Status) { '[✓]' } else { '[✗]' }
                $statusColor = if ($result.Status) { 'Green' } else { if ($result.Required) { 'Red' } else { 'Yellow' } }
                $reqText = if ($result.Required) { '(Required)' } else { '(Optional)' }
                Write-Host "$statusIcon $($result.Name) $reqText" -ForegroundColor $statusColor
                Write-Host "    $($result.Description)" -ForegroundColor Gray
            }
            Write-Host ""
        }

        return [PSCustomObject]@{
            OverallStatus = $overallStatus
            Results       = $results
            MissingRequired = $allRequired
        }
    }
}

function Initialize-WinPEBuilderEnvironment {
    <#
    .SYNOPSIS
        Initializes the WinPE Builder environment
    .DESCRIPTION
        Creates required directories, validates configuration, and prepares the build environment
    .PARAMETER Force
        Recreate directories even if they exist
    .EXAMPLE
        Initialize-WinPEBuilderEnvironment -Force
    #>
    [CmdletBinding(SupportsShouldProcess)]
    param(
        [Parameter()]
        [switch]$Force
    )

    begin {
        Write-WPELog -Message 'Initializing WinPE Builder environment' -Level 'Information'
    }

    process {
        try {
            # Load configuration
            $config = Get-WinPEBuilderConfig

            # Create required directories
            $directories = @(
                $script:OutputPath,
                $script:TempPath,
                $script:LogPath,
                (Join-Path -Path $script:OutputPath -ChildPath 'Mount'),
                (Join-Path -Path $script:OutputPath -ChildPath 'ISO'),
                (Join-Path -Path $script:OutputPath -ChildPath 'USB'),
                (Join-Path -Path $script:TempPath -ChildPath 'Downloads'),
                (Join-Path -Path $script:TempPath -ChildPath 'Extract'),
                (Join-Path -Path $script:WinPEBuilderRoot -ChildPath 'Tools'),
                (Join-Path -Path $script:WinPEBuilderRoot -ChildPath 'Drivers')
            )

            foreach ($dir in $directories) {
                if (-not (Test-Path -Path $dir) -or $Force) {
                    if ($PSCmdlet.ShouldProcess($dir, 'Create directory')) {
                        New-Item -Path $dir -ItemType Directory -Force | Out-Null
                        Write-WPELog -Message "Created directory: $dir" -Level 'Verbose'
                    }
                }
            }

            # Validate ADK installation
            $prereqs = Test-WinPEBuilderPrerequisites
            if (-not $prereqs.OverallStatus) {
                $missing = ($prereqs.MissingRequired | ForEach-Object { $_.Name }) -join ', '
                throw "Missing required prerequisites: $missing"
            }

            # Set environment variables for ADK tools
            $adkPath = $config.build.adkPath
            if (Test-Path -Path $adkPath) {
                $deployToolsPath = Join-Path -Path $adkPath -ChildPath 'Deployment Tools\amd64'
                $env:Path = "$deployToolsPath;$env:Path"

                $oscdimgPath = Join-Path -Path $deployToolsPath -ChildPath 'Oscdimg'
                $env:Path = "$oscdimgPath;$env:Path"
            }

            Write-WPELog -Message 'Environment initialized successfully' -Level 'Information'

            return [PSCustomObject]@{
                Status       = 'Initialized'
                OutputPath   = $script:OutputPath
                TempPath     = $script:TempPath
                LogPath      = $script:LogPath
                ADKPath      = $adkPath
                Directories  = $directories
            }
        }
        catch {
            Write-WPELog -Message "Failed to initialize environment: $_" -Level 'Error'
            throw
        }
    }
}
#endregion

#region Main Build Functions
function New-WinPEBuild {
    <#
    .SYNOPSIS
        Creates a new WinPE/WinRE build
    .DESCRIPTION
        Orchestrates the complete WinPE build process including:
        - WIM creation/extraction
        - Package installation
        - Tool integration
        - Driver injection
        - GUI setup
        - ISO/USB creation
    .PARAMETER BuildName
        Name for this build (used in output filenames)
    .PARAMETER ConfigPath
        Optional custom configuration file path
    .PARAMETER SkipTools
        Skip tool integration
    .PARAMETER SkipDrivers
        Skip driver injection
    .PARAMETER SkipGUI
        Skip GUI setup
    .PARAMETER OutputType
        Type of output: ISO, USB, or Both
    .PARAMETER USBDriveLetter
        Drive letter for USB output (if applicable)
    .EXAMPLE
        New-WinPEBuild -BuildName 'CustomPE' -OutputType Both
    .EXAMPLE
        New-WinPEBuild -BuildName 'RecoveryPE' -SkipGUI -OutputType ISO
    #>
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateNotNullOrEmpty()]
        [string]$BuildName,

        [Parameter()]
        [ValidateScript({ Test-Path -Path $_ -PathType Leaf })]
        [string]$ConfigPath,

        [Parameter()]
        [switch]$SkipTools,

        [Parameter()]
        [switch]$SkipDrivers,

        [Parameter()]
        [switch]$SkipGUI,

        [Parameter()]
        [ValidateSet('ISO', 'USB', 'Both')]
        [string]$OutputType = 'Both',

        [Parameter()]
        [ValidatePattern('^[A-Z]:?$')]
        [string]$USBDriveLetter
    )

    begin {
        $buildStartTime = Get-Date
        $buildId = [guid]::NewGuid().ToString('N').Substring(0, 8)

        Write-WPELog -Message "Starting WinPE build: $BuildName (ID: $buildId)" -Level 'Information'
        Write-Host ''
        Write-Host '╔══════════════════════════════════════════════════════════════╗' -ForegroundColor Cyan
        Write-Host '║           WinPE Builder Suite - Build Process                 ║' -ForegroundColor Cyan
        Write-Host '╚══════════════════════════════════════════════════════════════╝' -ForegroundColor Cyan
        Write-Host ''
    }

    process {
        try {
            # Initialize build session
            $script:CurrentBuildSession = [PSCustomObject]@{
                BuildId      = $buildId
                BuildName    = $BuildName
                StartTime    = $buildStartTime
                Status       = 'InProgress'
                Steps        = [List[PSCustomObject]]::new()
                Errors       = [List[string]]::new()
                Warnings     = [List[string]]::new()
            }

            # Step 1: Initialize environment
            Write-WPEProgress -Activity 'WinPE Build' -Status 'Initializing environment...' -PercentComplete 5
            $envResult = Initialize-WinPEBuilderEnvironment
            Add-BuildStep -Name 'Initialize Environment' -Status 'Completed'

            # Step 2: Load configuration
            Write-WPEProgress -Activity 'WinPE Build' -Status 'Loading configuration...' -PercentComplete 10
            $config = if ($ConfigPath) {
                Get-WinPEBuilderConfig -ConfigPath $ConfigPath
            } else {
                Get-WinPEBuilderConfig
            }
            Add-BuildStep -Name 'Load Configuration' -Status 'Completed'

            # Step 3: Create base WinPE WIM
            Write-WPEProgress -Activity 'WinPE Build' -Status 'Creating base WinPE...' -PercentComplete 15
            $wimParams = @{
                BuildName   = $BuildName
                OutputPath  = $script:OutputPath
                Architecture = $config.build.architecture
            }

            if ($config.build.wimSource -eq 'ISO' -and $config.build.windowsISOPath) {
                $wimParams['SourceISO'] = $config.build.windowsISOPath
            }

            $wimResult = New-WinPEWim @wimParams
            Add-BuildStep -Name 'Create Base WIM' -Status 'Completed' -Details "WIM: $($wimResult.WimPath)"

            # Step 4: Mount WIM
            Write-WPEProgress -Activity 'WinPE Build' -Status 'Mounting WIM for customization...' -PercentComplete 20
            $mountPath = Join-Path -Path $script:OutputPath -ChildPath "Mount\$BuildName"
            $mountResult = Mount-WinPEWim -WimPath $wimResult.WimPath -MountPath $mountPath
            Add-BuildStep -Name 'Mount WIM' -Status 'Completed' -Details "Mount: $mountPath"

            try {
                # Step 5: Add required WinPE packages
                Write-WPEProgress -Activity 'WinPE Build' -Status 'Installing WinPE packages...' -PercentComplete 30
                $packagesResult = Install-RequiredPackages -MountPath $mountPath -Config $config
                Add-BuildStep -Name 'Install Packages' -Status 'Completed' -Details "$($packagesResult.InstalledCount) packages"

                # Step 6: Integrate tools (unless skipped)
                if (-not $SkipTools) {
                    Write-WPEProgress -Activity 'WinPE Build' -Status 'Integrating tools...' -PercentComplete 45
                    $toolsResult = Install-AllWinPETools -MountPath $mountPath
                    Add-BuildStep -Name 'Integrate Tools' -Status 'Completed' -Details "$($toolsResult.InstalledCount) tools"
                } else {
                    Add-BuildStep -Name 'Integrate Tools' -Status 'Skipped'
                }

                # Step 7: Inject drivers (unless skipped)
                if (-not $SkipDrivers) {
                    Write-WPEProgress -Activity 'WinPE Build' -Status 'Injecting drivers...' -PercentComplete 55
                    $driversResult = Install-WinPEDrivers -MountPath $mountPath
                    Add-BuildStep -Name 'Inject Drivers' -Status 'Completed' -Details "$($driversResult.InjectedCount) drivers"
                } else {
                    Add-BuildStep -Name 'Inject Drivers' -Status 'Skipped'
                }

                # Step 8: Setup GUI (unless skipped)
                if (-not $SkipGUI) {
                    Write-WPEProgress -Activity 'WinPE Build' -Status 'Setting up GUI...' -PercentComplete 65
                    $guiResult = Install-WinPEGUI -MountPath $mountPath -Config $config
                    Add-BuildStep -Name 'Setup GUI' -Status 'Completed'
                } else {
                    Add-BuildStep -Name 'Setup GUI' -Status 'Skipped'
                }

                # Step 9: Configure startup scripts
                Write-WPEProgress -Activity 'WinPE Build' -Status 'Configuring startup...' -PercentComplete 75
                $startupResult = Set-WinPEStartup -MountPath $mountPath -Config $config
                Add-BuildStep -Name 'Configure Startup' -Status 'Completed'

                # Step 10: Optimize WIM
                Write-WPEProgress -Activity 'WinPE Build' -Status 'Optimizing WIM...' -PercentComplete 80
                $optimizeResult = Optimize-WinPEWim -MountPath $mountPath
                Add-BuildStep -Name 'Optimize WIM' -Status 'Completed'
            }
            finally {
                # Step 11: Dismount WIM
                Write-WPEProgress -Activity 'WinPE Build' -Status 'Saving and dismounting WIM...' -PercentComplete 85
                Dismount-WinPEWim -MountPath $mountPath -Save
                Add-BuildStep -Name 'Dismount WIM' -Status 'Completed'
            }

            # Step 12: Create output media
            $outputResult = $null

            if ($OutputType -eq 'ISO' -or $OutputType -eq 'Both') {
                Write-WPEProgress -Activity 'WinPE Build' -Status 'Creating ISO...' -PercentComplete 90
                $isoPath = Join-Path -Path $script:OutputPath -ChildPath "ISO\$BuildName.iso"
                $isoResult = New-WinPEISO -WimPath $wimResult.WimPath -OutputPath $isoPath -BootType UEFI
                Add-BuildStep -Name 'Create ISO' -Status 'Completed' -Details $isoPath
                $outputResult = $isoResult
            }

            if (($OutputType -eq 'USB' -or $OutputType -eq 'Both') -and $USBDriveLetter) {
                Write-WPEProgress -Activity 'WinPE Build' -Status 'Creating bootable USB...' -PercentComplete 95
                $usbResult = New-WinPEUSB -WimPath $wimResult.WimPath -DriveLetter $USBDriveLetter
                Add-BuildStep -Name 'Create USB' -Status 'Completed' -Details $USBDriveLetter
                $outputResult = $usbResult
            }

            # Complete build
            Write-WPEProgress -Activity 'WinPE Build' -Status 'Build completed!' -PercentComplete 100 -Completed

            $buildEndTime = Get-Date
            $buildDuration = $buildEndTime - $buildStartTime

            $script:CurrentBuildSession.Status = 'Completed'
            $script:CurrentBuildSession.EndTime = $buildEndTime
            $script:CurrentBuildSession.Duration = $buildDuration

            # Display summary
            Write-BuildSummary

            return [PSCustomObject]@{
                BuildId     = $buildId
                BuildName   = $BuildName
                Status      = 'Completed'
                Duration    = $buildDuration
                WimPath     = $wimResult.WimPath
                ISOPath     = if ($isoResult) { $isoResult.ISOPath } else { $null }
                USBDrive    = $USBDriveLetter
                Steps       = $script:CurrentBuildSession.Steps
                Errors      = $script:CurrentBuildSession.Errors
                Warnings    = $script:CurrentBuildSession.Warnings
            }
        }
        catch {
            $script:CurrentBuildSession.Status = 'Failed'
            $script:CurrentBuildSession.Errors.Add($_.Exception.Message)

            Write-WPELog -Message "Build failed: $_" -Level 'Error'

            # Cleanup on failure
            if ($mountPath -and (Test-Path -Path $mountPath)) {
                Write-WPELog -Message 'Attempting cleanup of mounted WIM...' -Level 'Warning'
                Dismount-WinPEWim -MountPath $mountPath -Discard -ErrorAction SilentlyContinue
            }

            throw
        }
    }
}

function Add-BuildStep {
    <#
    .SYNOPSIS
        Adds a step to the current build session
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$Name,

        [Parameter(Mandatory = $true)]
        [ValidateSet('Completed', 'Failed', 'Skipped', 'InProgress')]
        [string]$Status,

        [Parameter()]
        [string]$Details
    )

    if ($script:CurrentBuildSession) {
        $script:CurrentBuildSession.Steps.Add([PSCustomObject]@{
            Name      = $Name
            Status    = $Status
            Details   = $Details
            Timestamp = Get-Date
        })
    }
}

function Write-BuildSummary {
    <#
    .SYNOPSIS
        Displays the build summary
    #>
    [CmdletBinding()]
    param()

    if (-not $script:CurrentBuildSession) {
        return
    }

    $session = $script:CurrentBuildSession

    Write-Host ''
    Write-Host '╔══════════════════════════════════════════════════════════════╗' -ForegroundColor Green
    Write-Host '║                    BUILD SUMMARY                              ║' -ForegroundColor Green
    Write-Host '╚══════════════════════════════════════════════════════════════╝' -ForegroundColor Green
    Write-Host ''
    Write-Host "Build ID:    $($session.BuildId)" -ForegroundColor White
    Write-Host "Build Name:  $($session.BuildName)" -ForegroundColor White
    Write-Host "Status:      $($session.Status)" -ForegroundColor $(if ($session.Status -eq 'Completed') { 'Green' } else { 'Red' })
    Write-Host "Duration:    $($session.Duration.ToString('hh\:mm\:ss'))" -ForegroundColor White
    Write-Host ''
    Write-Host 'Steps:' -ForegroundColor Yellow

    foreach ($step in $session.Steps) {
        $icon = switch ($step.Status) {
            'Completed' { '[✓]'; 'Green' }
            'Failed' { '[✗]'; 'Red' }
            'Skipped' { '[-]'; 'Yellow' }
            default { '[?]'; 'Gray' }
        }
        $color = switch ($step.Status) {
            'Completed' { 'Green' }
            'Failed' { 'Red' }
            'Skipped' { 'Yellow' }
            default { 'Gray' }
        }
        Write-Host "  $icon $($step.Name)" -ForegroundColor $color
        if ($step.Details) {
            Write-Host "      $($step.Details)" -ForegroundColor DarkGray
        }
    }

    if ($session.Errors.Count -gt 0) {
        Write-Host ''
        Write-Host 'Errors:' -ForegroundColor Red
        foreach ($error in $session.Errors) {
            Write-Host "  - $error" -ForegroundColor Red
        }
    }

    if ($session.Warnings.Count -gt 0) {
        Write-Host ''
        Write-Host 'Warnings:' -ForegroundColor Yellow
        foreach ($warning in $session.Warnings) {
            Write-Host "  - $warning" -ForegroundColor Yellow
        }
    }

    Write-Host ''
}
#endregion

#region Helper Functions
function Install-RequiredPackages {
    <#
    .SYNOPSIS
        Installs required WinPE packages
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$MountPath,

        [Parameter(Mandatory = $true)]
        [PSCustomObject]$Config
    )

    $installedCount = 0
    $toolManifestPath = Join-Path -Path $script:ConfigPath -ChildPath 'ToolManifest.json'
    $toolManifest = Get-Content -Path $toolManifestPath -Raw | ConvertFrom-Json

    $packages = $toolManifest.winpePackages.required + $toolManifest.winpePackages.optional

    foreach ($package in $packages) {
        try {
            Add-WinPEPackage -MountPath $MountPath -PackageName $package -ErrorAction SilentlyContinue
            $installedCount++
        }
        catch {
            Write-WPELog -Message "Failed to install package $package`: $_" -Level 'Warning'
        }
    }

    return [PSCustomObject]@{
        InstalledCount = $installedCount
        TotalPackages  = $packages.Count
    }
}

function Install-WinPEGUI {
    <#
    .SYNOPSIS
        Installs GUI components
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$MountPath,

        [Parameter(Mandatory = $true)]
        [PSCustomObject]$Config
    )

    # Install WinXShell if configured
    if ($Config.gui.primaryShell -eq 'WinXShell') {
        Install-WinXShell -MountPath $MountPath
    }

    # Install PowerShell GUI
    if ($Config.gui.shell -eq 'Combination' -or $Config.gui.fallbackShell -eq 'PowerShellGUI') {
        Install-PowerShellGUI -MountPath $MountPath
    }

    # Apply theme
    Set-WinPETheme -MountPath $MountPath -Theme $Config.gui.theme.defaultMode

    return [PSCustomObject]@{
        Shell = $Config.gui.primaryShell
        Theme = $Config.gui.theme.defaultMode
    }
}

function Set-WinPEStartup {
    <#
    .SYNOPSIS
        Configures WinPE startup scripts
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$MountPath,

        [Parameter(Mandatory = $true)]
        [PSCustomObject]$Config
    )

    $startupScript = @'
@echo off
wpeinit
cd /d X:\Windows\System32

REM Initialize PowerShell environment
if exist "X:\Tools\DevTools\PowerShell7\pwsh.exe" (
    set PATH=X:\Tools\DevTools\PowerShell7;%PATH%
)

REM Load drivers dynamically
if exist "X:\Drivers" (
    for /r "X:\Drivers" %%d in (*.inf) do (
        drvload "%%d" >nul 2>&1
    )
)

REM Initialize network
wpeutil InitializeNetwork >nul 2>&1

REM Start GUI shell
if exist "X:\Tools\Interface\WinXShell\WinXShell.exe" (
    start "" "X:\Tools\Interface\WinXShell\WinXShell.exe"
) else if exist "X:\Tools\Interface\pecmd.exe" (
    start "" "X:\Tools\Interface\pecmd.exe" MAIN
) else (
    start cmd.exe
)
'@

    $startnetPath = Join-Path -Path $MountPath -ChildPath 'Windows\System32\startnet.cmd'
    $startupScript | Set-Content -Path $startnetPath -Encoding ASCII -Force

    return [PSCustomObject]@{
        StartupScript = $startnetPath
    }
}
#endregion

