#Requires -Version 5.1
#Requires -RunAsAdministrator
<#
.SYNOPSIS
    WimManager Module - WIM/ESD/FFU Operations
.DESCRIPTION
    Provides comprehensive WIM file management including creation, mounting,
    package management, driver injection, and format conversion.
.NOTES
    Part of WinPE-Builder-Suite
#>

using namespace System.IO
using namespace System.Collections.Generic

#region Module Variables
$script:ModuleRoot = $PSScriptRoot
$script:MountedImages = [Dictionary[string, PSCustomObject]]::new()
#endregion

#region WIM Creation
function New-WinPEWim {
    <#
    .SYNOPSIS
        Creates a new WinPE WIM file
    .DESCRIPTION
        Creates a base WinPE WIM from ADK installation or Windows ISO
    .PARAMETER BuildName
        Name for the WIM file
    .PARAMETER OutputPath
        Directory to save the WIM
    .PARAMETER Architecture
        Target architecture (amd64, x86, arm64)
    .PARAMETER SourceISO
        Optional Windows ISO to extract boot.wim from
    .PARAMETER ADKPath
        Optional custom ADK installation path
    .EXAMPLE
        New-WinPEWim -BuildName 'CustomPE' -OutputPath 'C:\WinPE\Output'
    #>
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateNotNullOrEmpty()]
        [string]$BuildName,

        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Container })]
        [string]$OutputPath,

        [Parameter()]
        [ValidateSet('amd64', 'x86', 'arm64')]
        [string]$Architecture = 'amd64',

        [Parameter()]
        [ValidateScript({ Test-Path -Path $_ -PathType Leaf })]
        [string]$SourceISO,

        [Parameter()]
        [string]$ADKPath
    )

    begin {
        Write-Verbose "Creating WinPE WIM: $BuildName"

        # Determine ADK path
        if (-not $ADKPath) {
            $ADKPath = Get-ADKInstallPath
        }

        if (-not (Test-Path -Path $ADKPath)) {
            throw "Windows ADK not found at: $ADKPath"
        }
    }

    process {
        try {
            $wimOutputPath = Join-Path -Path $OutputPath -ChildPath "$BuildName.wim"
            $workingDir = Join-Path -Path $OutputPath -ChildPath "WinPE_$Architecture"

            if ($SourceISO) {
                # Extract boot.wim from ISO
                Write-Verbose "Extracting boot.wim from ISO: $SourceISO"
                $extractedWim = Export-BootWimFromISO -ISOPath $SourceISO -OutputPath $OutputPath

                # Export index 1 (WinPE) to new WIM
                if ($PSCmdlet.ShouldProcess($wimOutputPath, 'Create WIM from ISO')) {
                    $dismArgs = @(
                        '/Export-Image'
                        "/SourceImageFile:`"$extractedWim`""
                        '/SourceIndex:1'
                        "/DestinationImageFile:`"$wimOutputPath`""
                        '/DestinationName:WinPE'
                        '/Compress:max'
                    )

                    $result = & dism.exe @dismArgs 2>&1
                    if ($LASTEXITCODE -ne 0) {
                        throw "DISM export failed: $result"
                    }
                }
            }
            else {
                # Create from ADK
                Write-Verbose "Creating WinPE from ADK"
                $winpeOCsPath = Join-Path -Path $ADKPath -ChildPath "Windows Preinstallation Environment\$Architecture\WinPE_OCs"
                $sourceWim = Join-Path -Path $ADKPath -ChildPath "Windows Preinstallation Environment\$Architecture\en-us\winpe.wim"

                if (-not (Test-Path -Path $sourceWim)) {
                    throw "WinPE source WIM not found: $sourceWim"
                }

                # Create working directory structure
                if ($PSCmdlet.ShouldProcess($workingDir, 'Create WinPE working directory')) {
                    # Use copype.cmd from ADK
                    $copypePath = Join-Path -Path $ADKPath -ChildPath 'Windows Preinstallation Environment\copype.cmd'

                    if (Test-Path -Path $copypePath) {
                        $env:WinPERoot = Join-Path -Path $ADKPath -ChildPath 'Windows Preinstallation Environment'
                        & cmd.exe /c "`"$copypePath`" $Architecture `"$workingDir`"" 2>&1 | Out-Null
                    }
                    else {
                        # Manual creation
                        New-Item -Path $workingDir -ItemType Directory -Force | Out-Null
                        New-Item -Path (Join-Path -Path $workingDir -ChildPath 'media\sources') -ItemType Directory -Force | Out-Null
                        New-Item -Path (Join-Path -Path $workingDir -ChildPath 'mount') -ItemType Directory -Force | Out-Null

                        # Copy boot files
                        $bootFilesPath = Join-Path -Path $ADKPath -ChildPath "Windows Preinstallation Environment\$Architecture\Media"
                        if (Test-Path -Path $bootFilesPath) {
                            Copy-Item -Path "$bootFilesPath\*" -Destination (Join-Path -Path $workingDir -ChildPath 'media') -Recurse -Force
                        }

                        # Copy WIM
                        Copy-Item -Path $sourceWim -Destination (Join-Path -Path $workingDir -ChildPath 'media\sources\boot.wim') -Force
                    }

                    # Copy final WIM to output
                    $sourceBootWim = Join-Path -Path $workingDir -ChildPath 'media\sources\boot.wim'
                    Copy-Item -Path $sourceBootWim -Destination $wimOutputPath -Force
                }
            }

            # Get WIM information
            $wimInfo = Get-WindowsImage -ImagePath $wimOutputPath

            return [PSCustomObject]@{
                WimPath      = $wimOutputPath
                Architecture = $Architecture
                ImageCount   = $wimInfo.Count
                ImageInfo    = $wimInfo
                WorkingDir   = $workingDir
                Source       = if ($SourceISO) { 'ISO' } else { 'ADK' }
                CreatedAt    = Get-Date
            }
        }
        catch {
            Write-Error "Failed to create WinPE WIM: $_"
            throw
        }
    }
}

function Export-BootWimFromISO {
    <#
    .SYNOPSIS
        Extracts boot.wim from a Windows ISO
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$ISOPath,

        [Parameter(Mandatory = $true)]
        [string]$OutputPath
    )

    try {
        # Mount ISO
        $mountResult = Mount-DiskImage -ImagePath $ISOPath -PassThru
        $driveLetter = ($mountResult | Get-Volume).DriveLetter

        try {
            $sourceWim = "${driveLetter}:\sources\boot.wim"

            if (-not (Test-Path -Path $sourceWim)) {
                throw "boot.wim not found in ISO"
            }

            $destWim = Join-Path -Path $OutputPath -ChildPath 'boot_extracted.wim'
            Copy-Item -Path $sourceWim -Destination $destWim -Force

            return $destWim
        }
        finally {
            Dismount-DiskImage -ImagePath $ISOPath | Out-Null
        }
    }
    catch {
        throw "Failed to extract boot.wim from ISO: $_"
    }
}
#endregion

#region WIM Mount/Dismount
function Mount-WinPEWim {
    <#
    .SYNOPSIS
        Mounts a WIM file for editing
    .DESCRIPTION
        Mounts a WIM image to a specified directory for customization
    .PARAMETER WimPath
        Path to the WIM file
    .PARAMETER MountPath
        Directory to mount the WIM to
    .PARAMETER Index
        Image index to mount (default: 1)
    .PARAMETER ReadOnly
        Mount as read-only
    .EXAMPLE
        Mount-WinPEWim -WimPath 'C:\WinPE\boot.wim' -MountPath 'C:\WinPE\Mount'
    #>
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Leaf })]
        [string]$WimPath,

        [Parameter(Mandatory = $true)]
        [string]$MountPath,

        [Parameter()]
        [ValidateRange(1, 99)]
        [int]$Index = 1,

        [Parameter()]
        [switch]$ReadOnly
    )

    begin {
        Write-Verbose "Mounting WIM: $WimPath to $MountPath"
    }

    process {
        try {
            # Check if already mounted
            $existingMount = Get-WindowsImage -Mounted | Where-Object { $_.Path -eq $MountPath }
            if ($existingMount) {
                throw "Mount path already in use: $MountPath"
            }

            # Create mount directory
            if (-not (Test-Path -Path $MountPath)) {
                New-Item -Path $MountPath -ItemType Directory -Force | Out-Null
            }

            if ($PSCmdlet.ShouldProcess($WimPath, "Mount image index $Index")) {
                $mountParams = @{
                    ImagePath = $WimPath
                    Path      = $MountPath
                    Index     = $Index
                }

                if ($ReadOnly) {
                    $mountParams['ReadOnly'] = $true
                }

                Mount-WindowsImage @mountParams

                # Track mounted image
                $script:MountedImages[$MountPath] = [PSCustomObject]@{
                    WimPath    = $WimPath
                    MountPath  = $MountPath
                    Index      = $Index
                    ReadOnly   = $ReadOnly
                    MountedAt  = Get-Date
                }

                return [PSCustomObject]@{
                    WimPath   = $WimPath
                    MountPath = $MountPath
                    Index     = $Index
                    ReadOnly  = $ReadOnly
                    Status    = 'Mounted'
                }
            }
        }
        catch {
            Write-Error "Failed to mount WIM: $_"
            throw
        }
    }
}

function Dismount-WinPEWim {
    <#
    .SYNOPSIS
        Dismounts a mounted WIM file
    .DESCRIPTION
        Saves changes and dismounts a WIM image
    .PARAMETER MountPath
        Path where the WIM is mounted
    .PARAMETER Save
        Save changes before dismounting
    .PARAMETER Discard
        Discard changes and dismount
    .EXAMPLE
        Dismount-WinPEWim -MountPath 'C:\WinPE\Mount' -Save
    #>
    [CmdletBinding(SupportsShouldProcess, DefaultParameterSetName = 'Save')]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Container })]
        [string]$MountPath,

        [Parameter(ParameterSetName = 'Save')]
        [switch]$Save,

        [Parameter(ParameterSetName = 'Discard')]
        [switch]$Discard
    )

    begin {
        Write-Verbose "Dismounting WIM from: $MountPath"
    }

    process {
        try {
            $action = if ($Discard) { 'Discard' } else { 'Save' }

            if ($PSCmdlet.ShouldProcess($MountPath, "Dismount WIM ($action changes)")) {
                $dismountParams = @{
                    Path = $MountPath
                }

                if ($Discard) {
                    $dismountParams['Discard'] = $true
                }
                else {
                    $dismountParams['Save'] = $true
                }

                Dismount-WindowsImage @dismountParams

                # Remove from tracked mounts
                if ($script:MountedImages.ContainsKey($MountPath)) {
                    $script:MountedImages.Remove($MountPath)
                }

                return [PSCustomObject]@{
                    MountPath = $MountPath
                    Action    = $action
                    Status    = 'Dismounted'
                }
            }
        }
        catch {
            Write-Error "Failed to dismount WIM: $_"
            throw
        }
    }
}
#endregion

#region Package Management
function Add-WinPEPackage {
    <#
    .SYNOPSIS
        Adds a package to a mounted WinPE image
    .DESCRIPTION
        Installs WinPE optional components (OCs) to a mounted image
    .PARAMETER MountPath
        Path where the WIM is mounted
    .PARAMETER PackageName
        Name of the package to install (e.g., 'WinPE-PowerShell')
    .PARAMETER PackagePath
        Optional direct path to package CAB file
    .EXAMPLE
        Add-WinPEPackage -MountPath 'C:\WinPE\Mount' -PackageName 'WinPE-PowerShell'
    #>
    [CmdletBinding(SupportsShouldProcess)]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Container })]
        [string]$MountPath,

        [Parameter(Mandatory = $true, ParameterSetName = 'ByName')]
        [string]$PackageName,

        [Parameter(Mandatory = $true, ParameterSetName = 'ByPath')]
        [ValidateScript({ Test-Path -Path $_ -PathType Leaf })]
        [string]$PackagePath
    )

    begin {
        if ($PackageName) {
            Write-Verbose "Adding package: $PackageName"
        }
        else {
            Write-Verbose "Adding package from: $PackagePath"
        }
    }

    process {
        try {
            if ($PackageName) {
                # Find package in ADK
                $adkPath = Get-ADKInstallPath
                $architecture = 'amd64'  # Default, could be parameterized
                $ocsPath = Join-Path -Path $adkPath -ChildPath "Windows Preinstallation Environment\$architecture\WinPE_OCs"

                $packageCab = Join-Path -Path $ocsPath -ChildPath "$PackageName.cab"
                $languageCab = Join-Path -Path $ocsPath -ChildPath "en-us\${PackageName}_en-us.cab"

                if (-not (Test-Path -Path $packageCab)) {
                    throw "Package not found: $PackageName"
                }

                if ($PSCmdlet.ShouldProcess($MountPath, "Add package $PackageName")) {
                    # Add base package
                    Add-WindowsPackage -Path $MountPath -PackagePath $packageCab

                    # Add language pack if exists
                    if (Test-Path -Path $languageCab) {
                        Add-WindowsPackage -Path $MountPath -PackagePath $languageCab
                    }
                }
            }
            else {
                if ($PSCmdlet.ShouldProcess($MountPath, "Add package from $PackagePath")) {
                    Add-WindowsPackage -Path $MountPath -PackagePath $PackagePath
                }
            }

            return [PSCustomObject]@{
                MountPath   = $MountPath
                Package     = if ($PackageName) { $PackageName } else { Split-Path -Path $PackagePath -Leaf }
                Status      = 'Installed'
            }
        }
        catch {
            Write-Error "Failed to add package: $_"
            throw
        }
    }
}

