#region WIM Conversion
function Convert-WimToEsd {
    <#
    .SYNOPSIS
        Converts a WIM file to ESD format
    .PARAMETER WimPath
        Path to the source WIM file
    .PARAMETER OutputPath
        Path for the output ESD file
    .EXAMPLE
        Convert-WimToEsd -WimPath 'C:\boot.wim' -OutputPath 'C:\boot.esd'
    #>
    [CmdletBinding(SupportsShouldProcess)]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Leaf })]
        [string]$WimPath,

        [Parameter(Mandatory = $true)]
        [string]$OutputPath
    )

    process {
        try {
            if ($PSCmdlet.ShouldProcess($WimPath, 'Convert to ESD')) {
                $dismArgs = @(
                    '/Export-Image'
                    "/SourceImageFile:`"$WimPath`""
                    '/SourceIndex:1'
                    "/DestinationImageFile:`"$OutputPath`""
                    '/Compress:recovery'
                )

                $result = & dism.exe @dismArgs 2>&1

                if ($LASTEXITCODE -ne 0) {
                    throw "DISM conversion failed: $result"
                }

                return [PSCustomObject]@{
                    SourceWim  = $WimPath
                    OutputEsd  = $OutputPath
                    Status     = 'Converted'
                }
            }
        }
        catch {
            Write-Error "Failed to convert to ESD: $_"
