function Split-WinPEWim {
    <#
    .SYNOPSIS
        Splits a WIM file into multiple parts
    .PARAMETER WimPath
        Path to the source WIM file
    .PARAMETER OutputPath
        Path for the output split WIM files
    .PARAMETER SizeInMB
        Maximum size of each part in MB (default: 4000 for FAT32)
    .EXAMPLE
        Split-WinPEWim -WimPath 'C:\boot.wim' -OutputPath 'C:\boot.swm' -SizeInMB 4000
    #>
    [CmdletBinding(SupportsShouldProcess)]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Leaf })]
        [string]$WimPath,

        [Parameter(Mandatory = $true)]
        [string]$OutputPath,

        [Parameter()]
        [ValidateRange(100, 10000)]
        [int]$SizeInMB = 4000
    )

    process {
        try {
            if ($PSCmdlet.ShouldProcess($WimPath, "Split into ${SizeInMB}MB parts")) {
                $dismArgs = @(
                    '/Split-Image'
                    "/ImageFile:`"$WimPath`""
                    "/SWMFile:`"$OutputPath`""
                    "/FileSize:$SizeInMB"
                )

                $result = & dism.exe @dismArgs 2>&1

                if ($LASTEXITCODE -ne 0) {
                    throw "DISM split failed: $result"
                }

                # Count split files
                $baseName = [Path]::GetFileNameWithoutExtension($OutputPath)
                $directory = Split-Path -Path $OutputPath -Parent
                $splitFiles = Get-ChildItem -Path $directory -Filter "$baseName*.swm"

                return [PSCustomObject]@{
                    SourceWim  = $WimPath
                    OutputPath = $OutputPath
                    Parts      = $splitFiles.Count
                    SizePerPart = $SizeInMB
                    Files      = $splitFiles.FullName
                    Status     = 'Split'
                }
            }
        }
        catch {
            Write-Error "Failed to split WIM: $_"
            throw
        }
    }
}
#endregion

#region WIM Optimization
function Optimize-WinPEWim {
    <#
    .SYNOPSIS
        Optimizes a mounted WinPE image
    .DESCRIPTION
        Performs cleanup and optimization on a mounted WinPE image
    .PARAMETER MountPath
        Path where the WIM is mounted
    .EXAMPLE
        Optimize-WinPEWim -MountPath 'C:\WinPE\Mount'
    #>
    [CmdletBinding(SupportsShouldProcess)]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Container })]
        [string]$MountPath
    )

    process {
        try {
            $cleanupTasks = @(
                @{ Name = 'Cleanup unused files'; Action = {
                    # Remove unnecessary files
                    $pathsToRemove = @(
                        'Windows\SoftwareDistribution\*',
                        'Windows\Logs\*',
                        'Windows\Temp\*',
                        'Users\*\AppData\Local\Temp\*'
                    )

                    foreach ($path in $pathsToRemove) {
                        $fullPath = Join-Path -Path $MountPath -ChildPath $path
                        Remove-Item -Path $fullPath -Recurse -Force -ErrorAction SilentlyContinue
                    }
                }},
                @{ Name = 'Reset base'; Action = {
                    if ($PSCmdlet.ShouldProcess($MountPath, 'Cleanup image')) {
                        $dismArgs = @(
                            '/Image:' + $MountPath
                            '/Cleanup-Image'
                            '/StartComponentCleanup'
                            '/ResetBase'
                        )
                        & dism.exe @dismArgs 2>&1 | Out-Null
                    }
                }}
            )

            foreach ($task in $cleanupTasks) {
                Write-Verbose "Running: $($task.Name)"
                & $task.Action
            }

            return [PSCustomObject]@{
                MountPath = $MountPath
                Status    = 'Optimized'
                Tasks     = $cleanupTasks.Name
            }
        }
        catch {
            Write-Error "Failed to optimize WIM: $_"
            throw
        }
    }
}

function Export-WinPEWim {
    <#
    .SYNOPSIS
        Exports and optimizes a WIM file
    .PARAMETER SourceWim
        Path to the source WIM file
    .PARAMETER OutputPath
        Path for the optimized output WIM
    .PARAMETER Compress
        Compression type: none, fast, max, recovery
    .EXAMPLE
        Export-WinPEWim -SourceWim 'C:\boot.wim' -OutputPath 'C:\boot_optimized.wim' -Compress max
