        [Parameter(Mandatory = $true)]
        [string]$OutputPath,

        [Parameter()]
        [ValidateSet('none', 'fast', 'max', 'recovery')]
        [string]$Compress = 'max'
    )

    process {
        try {
            if ($PSCmdlet.ShouldProcess($SourceWim, 'Export WIM')) {
                Export-WindowsImage -SourceImagePath $SourceWim -SourceIndex 1 `
                    -DestinationImagePath $OutputPath -CompressionType $Compress

                return [PSCustomObject]@{
