#region Helper Functions
function Get-ADKInstallPath {
    <#
    .SYNOPSIS
        Gets the Windows ADK installation path
    #>
    [CmdletBinding()]
    [OutputType([string])]
    param()

    $possiblePaths = @(
        'C:\Program Files (x86)\Windows Kits\10\Assessment and Deployment Kit',
        "${env:ProgramFiles(x86)}\Windows Kits\10\Assessment and Deployment Kit",
        'C:\Program Files\Windows Kits\10\Assessment and Deployment Kit'
    )

    foreach ($path in $possiblePaths) {
        if (Test-Path -Path $path) {
            return $path
        }
    }

    # Try registry
    $regPath = 'HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows Kits\Installed Roots'
    if (Test-Path -Path $regPath) {
        $kitsRoot = Get-ItemProperty -Path $regPath -Name 'KitsRoot10' -ErrorAction SilentlyContinue
        if ($kitsRoot) {
            $adkPath = Join-Path -Path $kitsRoot.KitsRoot10 -ChildPath 'Assessment and Deployment Kit'
            if (Test-Path -Path $adkPath) {
                return $adkPath
            }
        }
    }

    throw 'Windows ADK installation not found'
}
#endregion

Export-ModuleMember -Function *

#Requires -Version 5.1
<#
.SYNOPSIS
    ToolManager Module - Tool Acquisition and Integration
.DESCRIPTION
    Manages downloading, updating, and integrating portable tools into WinPE
.NOTES
    Part of WinPE-Builder-Suite
#>

using namespace System.IO
using namespace System.Net
using namespace System.Collections.Generic

#region Module Variables
$script:ModuleRoot = $PSScriptRoot
$script:ToolsPath = $null
$script:DownloadPath = $null
$script:ToolManifest = $null
#endregion

#region Initialization
function Initialize-ToolManager {
    <#
    .SYNOPSIS
        Initializes the ToolManager module
    #>
    [CmdletBinding()]
    param(
        [Parameter()]
        [string]$BasePath
    )

    if (-not $BasePath) {
        $BasePath = Split-Path -Path (Split-Path -Path $script:ModuleRoot -Parent) -Parent
    }

    $script:ToolsPath = Join-Path -Path $BasePath -ChildPath 'Tools'
    $script:DownloadPath = Join-Path -Path $BasePath -ChildPath 'Temp\Downloads'

    # Ensure directories exist
    @($script:ToolsPath, $script:DownloadPath) | ForEach-Object {
        if (-not (Test-Path -Path $_)) {
            New-Item -Path $_ -ItemType Directory -Force | Out-Null
        }
    }

    # Load tool manifest
    $manifestPath = Join-Path -Path $BasePath -ChildPath 'Config\ToolManifest.json'
    if (Test-Path -Path $manifestPath) {
        $script:ToolManifest = Get-Content -Path $manifestPath -Raw | ConvertFrom-Json
    }
}
#endregion

#region Manifest Functions
function Get-ToolManifest {
    <#
    .SYNOPSIS
        Gets the tool manifest
    .DESCRIPTION
        Returns the complete tool manifest or filters by category
    .PARAMETER Category
        Optional category filter
    .PARAMETER ToolId
        Optional specific tool ID
    .EXAMPLE
        Get-ToolManifest
    .EXAMPLE
        Get-ToolManifest -Category 'FileManagement'
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param(
        [Parameter()]
        [string]$Category,

        [Parameter()]
        [string]$ToolId
    )

    begin {
        if (-not $script:ToolManifest) {
            Initialize-ToolManager
        }
    }

    process {
        if ($ToolId) {
            # Search all categories for specific tool
            foreach ($cat in $script:ToolManifest.categories.PSObject.Properties) {
                $tool = $cat.Value.tools | Where-Object { $_.id -eq $ToolId }
                if ($tool) {
                    return $tool
                }
            }
            return $null
        }
        elseif ($Category) {
            return $script:ToolManifest.categories.$Category
        }
        else {
            return $script:ToolManifest
        }
    }
}

function Get-ToolCategories {
    <#
    .SYNOPSIS
        Gets all tool categories
    #>
    [CmdletBinding()]
    [OutputType([string[]])]
    param()

    begin {
        if (-not $script:ToolManifest) {
            Initialize-ToolManager
        }
    }

    process {
        return $script:ToolManifest.categories.PSObject.Properties.Name
    }
}

function Get-AllTools {
    <#
    .SYNOPSIS
        Gets all tools from the manifest
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject[]])]
    param()

    begin {
        if (-not $script:ToolManifest) {
            Initialize-ToolManager
        }
    }

    process {
        $allTools = [List[PSCustomObject]]::new()

        foreach ($category in $script:ToolManifest.categories.PSObject.Properties) {
            foreach ($tool in $category.Value.tools) {
                $allTools.Add($tool)
            }
        }

        return $allTools
    }
}
#endregion

#region Download Functions
function Get-ToolDownloadUrl {
    <#
    .SYNOPSIS
        Resolves the actual download URL for a tool
    .DESCRIPTION
        Handles different download methods (Direct, GitHub, SourceForge, etc.)
    .PARAMETER Tool
        Tool object from manifest
    .EXAMPLE
        $url = Get-ToolDownloadUrl -Tool $toolObject
    #>
    [CmdletBinding()]
    [OutputType([string])]
    param(
        [Parameter(Mandatory = $true)]
        [PSCustomObject]$Tool
    )

    process {
        try {
            switch ($Tool.downloadMethod) {
                'Direct' {
                    return $Tool.downloadUrl
                }

                'GitHub' {
                    return Get-GitHubLatestRelease -Repo $Tool.githubRepo -AssetPattern $Tool.assetPattern
                }

                'SourceForge' {
                    return Get-SourceForgeDownload -ProjectUrl $Tool.downloadUrl
                }

                'WebScrape' {
                    return Get-WebScrapedUrl -Url $Tool.downloadUrl -Pattern $Tool.urlPattern
                }

                'Chocolatey' {
                    # Return chocolatey ID for later handling
                    return "choco:$($Tool.chocolateyId)"
                }

                'Winget' {
                    # Return winget ID for later handling
                    return "winget:$($Tool.wingetId)"
                }

                'WinPEBuiltin' {
                    # Built-in to WinPE, no download needed
                    return $null
                }

                default {
                    return $Tool.downloadUrl
                }
            }
        }
        catch {
            Write-Warning "Failed to resolve download URL for $($Tool.name): $_"
            return $Tool.downloadUrl
        }
    }
}

function Get-GitHubLatestRelease {
    <#
    .SYNOPSIS
        Gets the latest release download URL from GitHub
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$Repo,

        [Parameter(Mandatory = $true)]
        [string]$AssetPattern
    )

    process {
        try {
            $apiUrl = "https://api.github.com/repos/$Repo/releases/latest"

            $headers = @{
                'Accept' = 'application/vnd.github.v3+json'
                'User-Agent' = 'WinPE-Builder-Suite'
            }

            # Check for GitHub token in environment
            if ($env:GITHUB_TOKEN) {
                $headers['Authorization'] = "token $env:GITHUB_TOKEN"
            }

            $response = Invoke-RestMethod -Uri $apiUrl -Headers $headers -Method Get

            # Find matching asset
            $asset = $response.assets | Where-Object {
                $_.name -like $AssetPattern
            } | Select-Object -First 1

            if ($asset) {
                return $asset.browser_download_url
            }
            else {
                throw "No asset matching pattern '$AssetPattern' found"
            }
        }
        catch {
            throw "Failed to get GitHub release: $_"
        }
    }
}

function Get-SourceForgeDownload {
    <#
    .SYNOPSIS
        Gets download URL from SourceForge
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$ProjectUrl
    )

    process {
        # SourceForge provides direct download links with /download suffix
        if ($ProjectUrl -notmatch '/download$') {
            return "$ProjectUrl/download"
        }
        return $ProjectUrl
    }
}

function Get-WebScrapedUrl {
    <#
    .SYNOPSIS
        Scrapes a web page for download URL
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$Url,

        [Parameter()]
        [string]$Pattern
    )

    process {
        try {
            $response = Invoke-WebRequest -Uri $Url -UseBasicParsing

            if ($Pattern) {
                $match = $response.Content | Select-String -Pattern $Pattern -AllMatches
                if ($match.Matches) {
                    return $match.Matches[0].Value
                }
            }

            # Try to find download links
            $links = $response.Links | Where-Object { 
                $_.href -match '\.(zip|exe|7z|msi)$' 
            } | Select-Object -First 1

            if ($links) {
                $href = $links.href
                if ($href -notmatch '^https?://') {
                    # Relative URL
                    $baseUri = [Uri]$Url
                    $href = [Uri]::new($baseUri, $href).AbsoluteUri
                }
                return $href
            }

            throw "No download link found on page"
        }
        catch {
            throw "Failed to scrape URL: $_"
        }
    }
}

function Invoke-ToolDownload {
    <#
    .SYNOPSIS
        Downloads a tool
    .DESCRIPTION
        Downloads a tool from its source with progress indication and retry logic
    .PARAMETER Tool
        Tool object from manifest
    .PARAMETER OutputPath
        Directory to save the download
    .PARAMETER RetryCount
        Number of retry attempts
    .EXAMPLE
        Invoke-ToolDownload -Tool $toolObject -OutputPath 'C:\Downloads'
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true)]
        [PSCustomObject]$Tool,

        [Parameter()]
        [string]$OutputPath,

        [Parameter()]
        [int]$RetryCount = 3
    )

    begin {
        if (-not $OutputPath) {
            Initialize-ToolManager
            $OutputPath = $script:DownloadPath
        }

        if (-not (Test-Path -Path $OutputPath)) {
            New-Item -Path $OutputPath -ItemType Directory -Force | Out-Null
        }
    }

    process {
        $downloadUrl = Get-ToolDownloadUrl -Tool $Tool

        if (-not $downloadUrl) {
            Write-Verbose "$($Tool.name) is built-in, no download needed"
            return [PSCustomObject]@{
                Tool       = $Tool.name
                Status     = 'BuiltIn'
                Path       = $null
            }
        }

        # Handle package managers
        if ($downloadUrl -match '^choco:(.+)$') {
            return Install-ToolViaChocolatey -PackageId $Matches[1] -Tool $Tool
        }
        elseif ($downloadUrl -match '^winget:(.+)$') {
            return Install-ToolViaWinget -PackageId $Matches[1] -Tool $Tool
        }

        # Direct download
        $fileName = Get-FileNameFromUrl -Url $downloadUrl -DefaultName "$($Tool.id).zip"
        $outputFile = Join-Path -Path $OutputPath -ChildPath $fileName

        $attempt = 0
        $success = $false

        while (-not $success -and $attempt -lt $RetryCount) {
            $attempt++

            try {
                Write-Verbose "Downloading $($Tool.name) (attempt $attempt/$RetryCount)"
                Write-Host "  Downloading: $($Tool.name)" -ForegroundColor Cyan

                # Use BITS for large files, WebClient for smaller
                $useProgressBar = $true

                if ($useProgressBar) {
                    $webClient = [System.Net.WebClient]::new()
                    $webClient.Headers.Add('User-Agent', 'WinPE-Builder-Suite/1.0')

                    $progressHandler = {
                        param($sender, $e)
                        Write-Progress -Activity "Downloading $($Tool.name)" `
                            -Status "$($e.ProgressPercentage)% complete" `
                            -PercentComplete $e.ProgressPercentage
                    }

                    $webClient.add_DownloadProgressChanged($progressHandler)

                    $downloadTask = $webClient.DownloadFileTaskAsync($downloadUrl, $outputFile)

                    while (-not $downloadTask.IsCompleted) {
                        Start-Sleep -Milliseconds 100
                    }

                    if ($downloadTask.IsFaulted) {
                        throw $downloadTask.Exception
                    }

                    Write-Progress -Activity "Downloading $($Tool.name)" -Completed
                }
                else {
                    Invoke-WebRequest -Uri $downloadUrl -OutFile $outputFile -UseBasicParsing
                }

                # Verify download
                if (Test-Path -Path $outputFile) {
                    $fileInfo = Get-Item -Path $outputFile
                    if ($fileInfo.Length -gt 0) {
                        $success = $true
                        Write-Host "  ✓ Downloaded: $($Tool.name) ($([math]::Round($fileInfo.Length / 1MB, 2)) MB)" -ForegroundColor Green
                    }
                    else {
                        Remove-Item -Path $outputFile -Force
                        throw "Downloaded file is empty"
                    }
                }
            }
            catch {
                Write-Warning "Download attempt $attempt failed for $($Tool.name): $_"
                if ($attempt -lt $RetryCount) {
                    Start-Sleep -Seconds (5 * $attempt)  # Exponential backoff
                }
            }
        }

        if (-not $success) {
            return [PSCustomObject]@{
                Tool       = $Tool.name
                Status     = 'Failed'
                Error      = "Download failed after $RetryCount attempts"
                Path       = $null
            }
        }

        return [PSCustomObject]@{
            Tool       = $Tool.name
            Status     = 'Downloaded'
            Path       = $outputFile
            Url        = $downloadUrl
            Size       = (Get-Item -Path $outputFile).Length
        }
    }
}

function Get-FileNameFromUrl {
    <#
    .SYNOPSIS
        Extracts filename from URL
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$Url,

        [Parameter()]
        [string]$DefaultName = 'download.zip'
    )

    try {
        $uri = [Uri]$Url
        $fileName = [Path]::GetFileName($uri.LocalPath)

        if ([string]::IsNullOrWhiteSpace($fileName) -or $fileName -eq '/') {
            return $DefaultName
        }

        # Clean up filename
        $fileName = $fileName -replace '[<>:"/\\|?*]', '_'

        return $fileName
    }
    catch {
        return $DefaultName
    }
}
#endregion

#region Package Manager Functions
function Install-ToolViaChocolatey {
    <#
    .SYNOPSIS
        Installs a tool via Chocolatey
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$PackageId,

        [Parameter(Mandatory = $true)]
        [PSCustomObject]$Tool
    )

    process {
        try {
            $chocoPath = Get-Command -Name 'choco' -ErrorAction SilentlyContinue
            if (-not $chocoPath) {
                throw "Chocolatey not installed"
            }

            Write-Host "  Installing via Chocolatey: $PackageId" -ForegroundColor Cyan

            $installPath = Join-Path -Path $script:ToolsPath -ChildPath $Tool.extractPath

            & choco install $PackageId -y --no-progress --install-arguments="'/D=$installPath'" 2>&1 | Out-Null

            if ($LASTEXITCODE -eq 0) {
                return [PSCustomObject]@{
                    Tool   = $Tool.name
                    Status = 'Installed'
                    Method = 'Chocolatey'
                    Path   = $installPath
                }
            }
            else {
                throw "Chocolatey installation failed"
            }
        }
        catch {
            Write-Warning "Chocolatey install failed for $($Tool.name): $_"
            return [PSCustomObject]@{
                Tool   = $Tool.name
                Status = 'Failed'
                Method = 'Chocolatey'
                Error  = $_.Exception.Message
            }
        }
    }
}

function Install-ToolViaWinget {
    <#
    .SYNOPSIS
        Installs a tool via Winget
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$PackageId,

        [Parameter(Mandatory = $true)]
        [PSCustomObject]$Tool
    )

    process {
        try {
            $wingetPath = Get-Command -Name 'winget' -ErrorAction SilentlyContinue
            if (-not $wingetPath) {
