#region Installation Functions
function Install-WinPETool {
    <#
    .SYNOPSIS
        Downloads and installs a single tool
    .DESCRIPTION
        Downloads, extracts, and integrates a tool into the WinPE tools directory
    .PARAMETER ToolId
        ID of the tool from manifest
    .PARAMETER Tool
        Tool object directly
    .PARAMETER MountPath
        Optional WinPE mount path for direct integration
    .EXAMPLE
        Install-WinPETool -ToolId '7zip'
    #>
    [CmdletBinding(DefaultParameterSetName = 'ById')]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true, ParameterSetName = 'ById')]
        [string]$ToolId,

        [Parameter(Mandatory = $true, ParameterSetName = 'ByObject')]
        [PSCustomObject]$Tool,

        [Parameter()]
        [string]$MountPath
    )

    begin {
        Initialize-ToolManager
    }

    process {
        try {
            # Get tool info
            if ($ToolId) {
                $Tool = Get-ToolManifest -ToolId $ToolId
                if (-not $Tool) {
                    throw "Tool not found: $ToolId"
                }
            }

            Write-Host "Installing: $($Tool.name)" -ForegroundColor Yellow

            # Download
            $downloadResult = Invoke-ToolDownload -Tool $Tool

            if ($downloadResult.Status -eq 'Failed') {
                return $downloadResult
            }

            if ($downloadResult.Status -eq 'BuiltIn') {
                return [PSCustomObject]@{
                    Tool     = $Tool.name
                    Status   = 'BuiltIn'
                    Path     = $null
                    Integrated = $false
                }
            }

            # Extract
            $extractPath = if ($MountPath) {
                Join-Path -Path $MountPath -ChildPath $Tool.extractPath
            }
            else {
                Join-Path -Path $script:ToolsPath -ChildPath $Tool.extractPath
            }

            $extractResult = Expand-ToolArchive -ArchivePath $downloadResult.Path -OutputPath $extractPath -Tool $Tool

            # Verify installation
            $executablePath = Join-Path -Path $extractPath -ChildPath $Tool.executable
            $installed = Test-Path -Path $executablePath

            if (-not $installed -and $Tool.executable) {
                # Try to find executable recursively
                $foundExe = Get-ChildItem -Path $extractPath -Filter $Tool.executable -Recurse -ErrorAction SilentlyContinue | Select-Object -First 1
                if ($foundExe) {
                    $installed = $true
                    $executablePath = $foundExe.FullName
                }
            }

            Write-Host "  ✓ Installed: $($Tool.name)" -ForegroundColor Green

            return [PSCustomObject]@{
                Tool         = $Tool.name
                ToolId       = $Tool.id
                Status       = if ($installed) { 'Installed' } else { 'Extracted' }
                Path         = $extractPath
                Executable   = $executablePath
                Category     = $Tool.category
            }
        }
        catch {
            Write-Host "  ✗ Failed: $($Tool.name) - $_" -ForegroundColor Red
            return [PSCustomObject]@{
                Tool   = $Tool.name
                Status = 'Failed'
                Error  = $_.Exception.Message
            }
        }
    }
}

function Expand-ToolArchive {
    <#
    .SYNOPSIS
        Extracts a tool archive
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$ArchivePath,

        [Parameter(Mandatory = $true)]
        [string]$OutputPath,

        [Parameter(Mandatory = $true)]
        [PSCustomObject]$Tool
    )

    process {
        try {
            # Create output directory
            if (-not (Test-Path -Path $OutputPath)) {
                New-Item -Path $OutputPath -ItemType Directory -Force | Out-Null
            }

            $extension = [Path]::GetExtension($ArchivePath).ToLower()

            switch ($extension) {
                '.zip' {
                    Expand-Archive -Path $ArchivePath -DestinationPath $OutputPath -Force
                }

                '.7z' {
                    # Try 7-Zip if available
                    $sevenZip = Get-Command -Name '7z' -ErrorAction SilentlyContinue
                    if (-not $sevenZip) {
                        $sevenZip = Get-Command -Name '7z.exe' -ErrorAction SilentlyContinue
                    }
                    if (-not $sevenZip) {
                        # Check common locations
                        $commonPaths = @(
                            'C:\Program Files\7-Zip\7z.exe',
                            'C:\Program Files (x86)\7-Zip\7z.exe'
                        )
                        foreach ($path in $commonPaths) {
                            if (Test-Path -Path $path) {
                                $sevenZip = $path
                                break
                            }
                        }
                    }

                    if ($sevenZip) {
                        & $sevenZip x "$ArchivePath" -o"$OutputPath" -y 2>&1 | Out-Null
                    }
                    else {
                        throw "7-Zip not found for .7z extraction"
                    }
                }

                '.exe' {
                    # Some exe files are self-extracting or portable
                    if ($Tool.extractArgs) {
                        # Self-extracting archive
                        $extractArgs = $Tool.extractArgs -replace '\{OUTPUT\}', $OutputPath
                        Start-Process -FilePath $ArchivePath -ArgumentList $extractArgs -Wait -NoNewWindow
                    }
                    else {
                        # Portable exe, just copy
                        Copy-Item -Path $ArchivePath -Destination $OutputPath -Force
                    }
                }

                '.msi' {
                    # Extract MSI
                    $msiExec = "msiexec /a `"$ArchivePath`" /qn TARGETDIR=`"$OutputPath`""
                    Start-Process -FilePath 'cmd.exe' -ArgumentList "/c $msiExec" -Wait -NoNewWindow
                }

                default {
                    # Try as zip
                    try {
                        Expand-Archive -Path $ArchivePath -DestinationPath $OutputPath -Force
                    }
                    catch {
                        # Copy as-is
                        Copy-Item -Path $ArchivePath -Destination $OutputPath -Force
                    }
                }
            }

            return [PSCustomObject]@{
                ArchivePath = $ArchivePath
                OutputPath  = $OutputPath
                Status      = 'Extracted'
            }
        }
        catch {
            throw "Failed to extract archive: $_"
        }
    }
}

function Install-AllWinPETools {
    <#
    .SYNOPSIS
        Downloads and installs all tools from manifest
    .DESCRIPTION
        Iterates through the tool manifest and installs all tools
    .PARAMETER MountPath
        Optional WinPE mount path for direct integration
    .PARAMETER Category
        Optional category filter
    .PARAMETER SkipExisting
        Skip tools that are already installed
    .EXAMPLE
        Install-AllWinPETools
    .EXAMPLE
        Install-AllWinPETools -Category 'FileManagement'
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param(
        [Parameter()]
        [string]$MountPath,

        [Parameter()]
        [string]$Category,

        [Parameter()]
        [switch]$SkipExisting
    )

    begin {
        Initialize-ToolManager
        $startTime = Get-Date
        $results = [List[PSCustomObject]]::new()
    }

    process {
        Write-Host ''
        Write-Host '╔══════════════════════════════════════════════════════════════╗' -ForegroundColor Cyan
        Write-Host '║              TOOL INSTALLATION PROCESS                        ║' -ForegroundColor Cyan
        Write-Host '╚══════════════════════════════════════════════════════════════╝' -ForegroundColor Cyan
        Write-Host ''

        $categories = if ($Category) {
            @($Category)
        }
        else {
            Get-ToolCategories
        }

        $totalTools = 0
        $installedCount = 0
        $skippedCount = 0
        $failedCount = 0

        foreach ($cat in $categories) {
            $categoryData = Get-ToolManifest -Category $cat

            if (-not $categoryData -or -not $categoryData.tools) {
                continue
            }

            Write-Host ''
            Write-Host "═══ $($categoryData.displayName) ═══" -ForegroundColor Yellow

            foreach ($tool in $categoryData.tools) {
                $totalTools++

                # Check if already installed
                if ($SkipExisting) {
                    $toolPath = Join-Path -Path $script:ToolsPath -ChildPath $tool.extractPath
                    if (Test-Path -Path $toolPath) {
                        Write-Host "  → Skipping (exists): $($tool.name)" -ForegroundColor DarkGray
                        $skippedCount++
                        $results.Add([PSCustomObject]@{
                            Tool   = $tool.name
                            Status = 'Skipped'
                            Reason = 'AlreadyExists'
                        })
                        continue
                    }
                }

                $installParams = @{
                    Tool = $tool
                }

                if ($MountPath) {
                    $installParams['MountPath'] = $MountPath
                }

                $result = Install-WinPETool @installParams
                $results.Add($result)

                if ($result.Status -eq 'Installed' -or $result.Status -eq 'Extracted') {
                    $installedCount++
                }
                elseif ($result.Status -eq 'Failed') {
                    $failedCount++
                }
            }
        }

        $endTime = Get-Date
        $duration = $endTime - $startTime

        # Summary
        Write-Host ''
        Write-Host '╔══════════════════════════════════════════════════════════════╗' -ForegroundColor Green
        Write-Host '║                INSTALLATION SUMMARY                           ║' -ForegroundColor Green
        Write-Host '╚══════════════════════════════════════════════════════════════╝' -ForegroundColor Green
        Write-Host ''
        Write-Host "  Total Tools:     $totalTools" -ForegroundColor White
        Write-Host "  Installed:       $installedCount" -ForegroundColor Green
        Write-Host "  Skipped:         $skippedCount" -ForegroundColor Yellow
        Write-Host "  Failed:          $failedCount" -ForegroundColor $(if ($failedCount -gt 0) { 'Red' } else { 'White' })
        Write-Host "  Duration:        $($duration.ToString('mm\:ss'))" -ForegroundColor White
        Write-Host ''

        return [PSCustomObject]@{
            TotalTools     = $totalTools
            InstalledCount = $installedCount
            SkippedCount   = $skippedCount
            FailedCount    = $failedCount
            Duration       = $duration
            Results        = $results
        }
    }
}
#endregion

#region Verification Functions
function Test-ToolAvailability {
    <#
    .SYNOPSIS
        Checks if a tool's download is available
    .PARAMETER ToolId
        ID of the tool to check
    .EXAMPLE
        Test-ToolAvailability -ToolId '7zip'
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true)]
        [string]$ToolId
    )

    process {
        $tool = Get-ToolManifest -ToolId $ToolId

        if (-not $tool) {
            return [PSCustomObject]@{
                ToolId    = $ToolId
                Available = $false
                Error     = 'Tool not found in manifest'
            }
        }

        try {
            $url = Get-ToolDownloadUrl -Tool $tool

            if (-not $url -or $url -match '^(choco|winget):') {
                return [PSCustomObject]@{
                    ToolId    = $ToolId
                    Tool      = $tool.name
                    Available = $true
                    Url       = $url
                    Method    = $tool.downloadMethod
                }
            }

            # Test URL availability
            $request = [System.Net.WebRequest]::Create($url)
            $request.Method = 'HEAD'
            $request.Timeout = 10000

            $response = $request.GetResponse()
            $statusCode = [int]$response.StatusCode
            $response.Close()

            return [PSCustomObject]@{
                ToolId     = $ToolId
                Tool       = $tool.name
                Available  = ($statusCode -ge 200 -and $statusCode -lt 400)
                Url        = $url
                StatusCode = $statusCode
            }
        }
        catch {
            return [PSCustomObject]@{
                ToolId    = $ToolId
                Tool      = $tool.name
                Available = $false
                Url       = $url
                Error     = $_.Exception.Message
            }
        }
    }
}

function Test-AllToolIntegrity {
    <#
    .SYNOPSIS
        Verifies all installed tools
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject[]])]
    param()

    begin {
        Initialize-ToolManager
        $results = [List[PSCustomObject]]::new()
    }

    process {
        $allTools = Get-AllTools

        foreach ($tool in $allTools) {
            $toolPath = Join-Path -Path $script:ToolsPath -ChildPath $tool.extractPath
            $execPath = Join-Path -Path $toolPath -ChildPath $tool.executable

            $exists = Test-Path -Path $toolPath
            $execExists = if ($tool.executable) { Test-Path -Path $execPath } else { $true }

            $results.Add([PSCustomObject]@{
                Tool          = $tool.name
                ToolId        = $tool.id
                Installed     = $exists
                ExecutableOK  = $execExists
                Path          = $toolPath
                ExecutablePath = $execPath
            })
        }

        return $results
    }
}

function Update-WinPETool {
    <#
    .SYNOPSIS
        Updates a tool to latest version
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$ToolId
    )

    process {
        $tool = Get-ToolManifest -ToolId $ToolId

        if (-not $tool) {
            throw "Tool not found: $ToolId"
        }

        # Remove existing
        $toolPath = Join-Path -Path $script:ToolsPath -ChildPath $tool.extractPath
        if (Test-Path -Path $toolPath) {
            Remove-Item -Path $toolPath -Recurse -Force
        }

        # Reinstall
        return Install-WinPETool -Tool $tool
    }
}

function Update-AllWinPETools {
    <#
    .SYNOPSIS
        Updates all tools to latest versions
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param()

    process {
        $allTools = Get-AllTools
        $results = [List[PSCustomObject]]::new()

        foreach ($tool in $allTools) {
            $result = Update-WinPETool -ToolId $tool.id
            $results.Add($result)
        }

        return [PSCustomObject]@{
            UpdatedCount = ($results | Where-Object { $_.Status -eq 'Installed' }).Count
            FailedCount  = ($results | Where-Object { $_.Status -eq 'Failed' }).Count
            Results      = $results
        }
    }
}

function Remove-WinPETool {
    <#
    .SYNOPSIS
        Removes an installed tool
    #>
    [CmdletBinding(SupportsShouldProcess)]
    param(
        [Parameter(Mandatory = $true)]
        [string]$ToolId
    )

    process {
        $tool = Get-ToolManifest -ToolId $ToolId

        if (-not $tool) {
            throw "Tool not found: $ToolId"
        }

        $toolPath = Join-Path -Path $script:ToolsPath -ChildPath $tool.extractPath

        if (Test-Path -Path $toolPath) {
            if ($PSCmdlet.ShouldProcess($toolPath, "Remove tool $($tool.name)")) {
                Remove-Item -Path $toolPath -Recurse -Force

                return [PSCustomObject]@{
                    Tool   = $tool.name
                    Status = 'Removed'
                    Path   = $toolPath
                }
            }
        }
        else {
            return [PSCustomObject]@{
                Tool   = $tool.name
                Status = 'NotFound'
                Path   = $toolPath
            }
        }
    }
}
#endregion

Export-ModuleMember -Function *

#Requires -Version 5.1
#Requires -RunAsAdministrator
<#
.SYNOPSIS
    DriverManager Module - Driver Scanning, Export, and Injection
.DESCRIPTION
    Manages driver operations including system scanning, export, download,
    CAB creation, and WinPE injection.
.NOTES
    Part of WinPE-Builder-Suite
#>

using namespace System.IO
using namespace System.Collections.Generic

#region Module Variables
$script:ModuleRoot = $PSScriptRoot
$script:DriversPath = $null
$script:DriverSources = $null
#endregion

#region Initialization
function Initialize-DriverManager {
    <#
    .SYNOPSIS
        Initializes the DriverManager module
    #>
    [CmdletBinding()]
    param(
        [Parameter()]
        [string]$BasePath
    )

    if (-not $BasePath) {
        $BasePath = Split-Path -Path (Split-Path -Path $script:ModuleRoot -Parent) -Parent
    }

    $script:DriversPath = Join-Path -Path $BasePath -ChildPath 'Drivers'

    # Ensure directories exist
    $subDirs = @('Exported', 'Downloaded', 'CABs', 'Staging')
    foreach ($dir in $subDirs) {
        $path = Join-Path -Path $script:DriversPath -ChildPath $dir
        if (-not (Test-Path -Path $path)) {
            New-Item -Path $path -ItemType Directory -Force | Out-Null
        }
    }

    # Load driver sources config
    $sourcesPath = Join-Path -Path $BasePath -ChildPath 'Config\DriverSources.json'
    if (Test-Path -Path $sourcesPath) {
        $script:DriverSources = Get-Content -Path $sourcesPath -Raw | ConvertFrom-Json
    }
}
#endregion

#region System Driver Functions
function Get-SystemDrivers {
    <#
    .SYNOPSIS
        Gets drivers installed on the current system
    .DESCRIPTION
        Retrieves a list of all third-party drivers installed on the system
    .PARAMETER ExcludeInbox
        Exclude Windows inbox drivers
    .PARAMETER ClassFilter
        Filter by driver class (Display, Net, etc.)
    .EXAMPLE
        Get-SystemDrivers -ExcludeInbox
    .EXAMPLE
        Get-SystemDrivers -ClassFilter 'Display','Net'
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject[]])]
    param(
        [Parameter()]
        [switch]$ExcludeInbox,

        [Parameter()]
        [string[]]$ClassFilter
    )

    begin {
        Write-Verbose "Scanning system drivers..."
    }

    process {
        try {
            # Get all drivers from driver store
            $drivers = Get-WindowsDriver -Online -All

            if ($ExcludeInbox) {
                $drivers = $drivers | Where-Object {
                    $_.Driver -notmatch '^oem\d+\.inf$' -eq $false -or
                    $_.ProviderName -ne 'Microsoft'
                }
            }

            if ($ClassFilter) {
                $drivers = $drivers | Where-Object { $_.ClassName -in $ClassFilter }
            }

            # Enhance driver information
            $results = foreach ($driver in $drivers) {
                $hwIds = try {
                    (Get-WindowsDriver -Online -Driver $driver.Driver).HardwareId
                } catch { @() }

                [PSCustomObject]@{
                    DriverName    = $driver.Driver
                    ClassName     = $driver.ClassName
                    ProviderName  = $driver.ProviderName
                    Version       = $driver.Version
                    Date          = $driver.Date
                    BootCritical  = $driver.BootCritical
                    OriginalName  = $driver.OriginalFileName
                    InBox         = $driver.Inbox
                    HardwareIds   = $hwIds
                    DriverStore   = "C:\Windows\System32\DriverStore\FileRepository\$($driver.Driver -replace '\.inf$', '')*"
                }
            }

            return $results | Sort-Object -Property ClassName, DriverName
        }
        catch {
            Write-Error "Failed to get system drivers: $_"
            throw
        }
    }
}

function Export-SystemDrivers {
    <#
    .SYNOPSIS
        Exports drivers from the current system
    .DESCRIPTION
        Exports third-party drivers to a specified directory for use in WinPE
    .PARAMETER OutputPath
        Directory to export drivers to
    .PARAMETER ClassFilter
        Filter by driver class
    .PARAMETER ExcludeInbox
        Exclude Windows inbox drivers
    .PARAMETER CreateCab
        Create a CAB file of exported drivers
    .EXAMPLE
        Export-SystemDrivers -OutputPath 'C:\Drivers\Exported'
    .EXAMPLE
        Export-SystemDrivers -ClassFilter 'Net','Display' -CreateCab
    #>
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([PSCustomObject])]
    param(
        [Parameter()]
        [string]$OutputPath,

        [Parameter()]
        [string[]]$ClassFilter,

        [Parameter()]
        [switch]$ExcludeInbox,

        [Parameter()]
        [switch]$CreateCab
    )

    begin {
        Initialize-DriverManager

        if (-not $OutputPath) {
            $OutputPath = Join-Path -Path $script:DriversPath -ChildPath 'Exported'
        }

        if (-not (Test-Path -Path $OutputPath)) {
            New-Item -Path $OutputPath -ItemType Directory -Force | Out-Null
        }
    }

    process {
        try {
            Write-Host ''
            Write-Host '╔══════════════════════════════════════════════════════════════╗' -ForegroundColor Cyan
            Write-Host '║              DRIVER EXPORT PROCESS                            ║' -ForegroundColor Cyan
            Write-Host '╚══════════════════════════════════════════════════════════════╝' -ForegroundColor Cyan
            Write-Host ''

            # Default classes for WinPE
            if (-not $ClassFilter) {
                $ClassFilter = @(
                    'Display',
                    'Net',
                    'Media',
                    'HDC',
                    'SCSIAdapter',
                    'USB',
                    'System',
                    'Bluetooth',
                    'MTD',
                    'SDHost'
                )
            }

            $exportedCount = 0
            $failedCount = 0
            $exportedDrivers = [List[PSCustomObject]]::new()

            if ($PSCmdlet.ShouldProcess($OutputPath, 'Export system drivers')) {
                # Use DISM to export drivers
                Write-Host "  Exporting drivers to: $OutputPath" -ForegroundColor Yellow

                $dismArgs = @(
                    '/Online'
                    '/Export-Driver'
                    "/Destination:`"$OutputPath`""
                )

                $result = & dism.exe @dismArgs 2>&1

                if ($LASTEXITCODE -eq 0) {
                    # Get exported drivers
                    $exportedInfs = Get-ChildItem -Path $OutputPath -Filter '*.inf' -Recurse

                    foreach ($inf in $exportedInfs) {
                        # Parse INF to get class
                        $infContent = Get-Content -Path $inf.FullName -Raw
                        $classMatch = $infContent | Select-String -Pattern 'Class\s*=\s*(.+)'
                        $className = if ($classMatch) { $classMatch.Matches[0].Groups[1].Value.Trim() } else { 'Unknown' }

                        if ($ClassFilter -contains $className -or $ClassFilter -contains 'All') {
                            $exportedCount++
                            $exportedDrivers.Add([PSCustomObject]@{
                                DriverName = $inf.Name
                                Class      = $className
                                Path       = $inf.DirectoryName
                            })
                            Write-Host "  ✓ $($inf.Name) ($className)" -ForegroundColor Green
                        }
                        else {
                            # Remove drivers not in filter
                            if ($ExcludeInbox) {
                                Remove-Item -Path $inf.DirectoryName -Recurse -Force -ErrorAction SilentlyContinue
                            }
                        }
                    }
                }
                else {
                    Write-Warning "DISM export returned errors: $result"
                }
            }

            # Create CAB if requested
            $cabPath = $null
            if ($CreateCab -and $exportedCount -gt 0) {
                $cabPath = New-DriverCab -SourcePath $OutputPath -OutputPath (Join-Path -Path $script:DriversPath -ChildPath 'CABs')
            }

            Write-Host ''
            Write-Host "  Export complete: $exportedCount drivers exported" -ForegroundColor Green
            Write-Host ''

            return [PSCustomObject]@{
                OutputPath     = $OutputPath
                ExportedCount  = $exportedCount
                FailedCount    = $failedCount
                Drivers        = $exportedDrivers
                CabPath        = $cabPath
            }
        }
        catch {
            Write-Error "Failed to export drivers: $_"
            throw
        }
    }
}
#endregion

#region Driver Download Functions
function Get-DriverDownloadUrls {
    <#
    .SYNOPSIS
        Gets driver download URLs for target hardware
    .DESCRIPTION
        Retrieves download URLs from manufacturer sites for specified hardware
    .PARAMETER Manufacturer
        Hardware manufacturer (ASUS, NVIDIA, Intel, etc.)
    .PARAMETER Model
        Hardware model
    .EXAMPLE
        Get-DriverDownloadUrls -Manufacturer 'NVIDIA' -Model 'RTX 3060 Ti'
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject[]])]
    param(
        [Parameter()]
        [string]$Manufacturer,

        [Parameter()]
        [string]$Model
    )

    begin {
        Initialize-DriverManager
    }

    process {
        $results = [List[PSCustomObject]]::new()

        if ($script:DriverSources -and $script:DriverSources.manufacturers) {
            foreach ($mfr in $script:DriverSources.manufacturers.PSObject.Properties) {
                if (-not $Manufacturer -or $mfr.Name -eq $Manufacturer) {
                    foreach ($driver in $mfr.Value.drivers) {
                        if (-not $Model -or $driver.name -match $Model) {
                            $results.Add([PSCustomObject]@{
                                Manufacturer = $mfr.Name
                                DriverName   = $driver.name
                                Category     = $driver.category
                                Version      = $driver.version
                                DownloadUrl  = $driver.downloadUrl
                                Required     = $driver.required
                            })
                        }
                    }
                }
            }
        }

        return $results
    }
}

function Invoke-DriverDownload {
    <#
    .SYNOPSIS
        Downloads drivers from manufacturer sites
    .PARAMETER DriverInfo
        Driver information object
    .PARAMETER OutputPath
        Directory to save downloaded drivers
    .EXAMPLE
        Invoke-DriverDownload -DriverInfo $driverObj
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true)]
        [PSCustomObject]$DriverInfo,

        [Parameter()]
        [string]$OutputPath
    )

    begin {
        Initialize-DriverManager

        if (-not $OutputPath) {
            $OutputPath = Join-Path -Path $script:DriversPath -ChildPath 'Downloaded'
        }

        if (-not (Test-Path -Path $OutputPath)) {
            New-Item -Path $OutputPath -ItemType Directory -Force | Out-Null
        }
    }

    process {
        try {
            $fileName = Split-Path -Path $DriverInfo.DownloadUrl -Leaf
            $downloadPath = Join-Path -Path $OutputPath -ChildPath $fileName

            Write-Host "  Downloading: $($DriverInfo.DriverName)" -ForegroundColor Cyan

            # Download with progress
            $webClient = [System.Net.WebClient]::new()
            $webClient.Headers.Add('User-Agent', 'WinPE-Builder-Suite/1.0')
            $webClient.DownloadFile($DriverInfo.DownloadUrl, $downloadPath)

            if (Test-Path -Path $downloadPath) {
                $fileInfo = Get-Item -Path $downloadPath
                Write-Host "  ✓ Downloaded: $($DriverInfo.DriverName) ($([math]::Round($fileInfo.Length / 1MB, 2)) MB)" -ForegroundColor Green

                # Extract if archive
                $extractPath = Join-Path -Path $OutputPath -ChildPath $DriverInfo.Category
                $extracted = Expand-DriverPackage -PackagePath $downloadPath -OutputPath $extractPath -DriverInfo $DriverInfo

                return [PSCustomObject]@{
                    DriverName   = $DriverInfo.DriverName
                    Status       = 'Downloaded'
                    DownloadPath = $downloadPath
                    ExtractPath  = $extractPath
                    Size         = $fileInfo.Length
                }
            }
            else {
                throw "Download verification failed"
            }
        }
        catch {
            Write-Host "  ✗ Failed: $($DriverInfo.DriverName) - $_" -ForegroundColor Red
            return [PSCustomObject]@{
                DriverName = $DriverInfo.DriverName
                Status     = 'Failed'
                Error      = $_.Exception.Message
            }
        }
    }
}

function Expand-DriverPackage {
    <#
    .SYNOPSIS
        Extracts a driver package
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$PackagePath,

        [Parameter(Mandatory = $true)]
        [string]$OutputPath,

        [Parameter()]
        [PSCustomObject]$DriverInfo
    )

    process {
        try {
            if (-not (Test-Path -Path $OutputPath)) {
                New-Item -Path $OutputPath -ItemType Directory -Force | Out-Null
            }

            $extension = [Path]::GetExtension($PackagePath).ToLower()

            switch ($extension) {
                '.zip' {
                    Expand-Archive -Path $PackagePath -DestinationPath $OutputPath -Force
                }
                '.exe' {
                    # NVIDIA and some drivers use self-extracting exe
                    if ($DriverInfo -and $DriverInfo.extractArgs) {
                        $extractArgs = $DriverInfo.extractArgs -replace '\{OUTPUT\}', $OutputPath
                        Start-Process -FilePath $PackagePath -ArgumentList $extractArgs -Wait -NoNewWindow
                    }
                    else {
                        # Try 7-Zip for extraction
                        $sevenZip = Get-SevenZipPath
                        if ($sevenZip) {
                            & $sevenZip x "$PackagePath" -o"$OutputPath" -y 2>&1 | Out-Null
                        }
                        else {
                            # Try as self-extracting
                            Start-Process -FilePath $PackagePath -ArgumentList "/s /e /f:`"$OutputPath`"" -Wait -NoNewWindow
                        }
                    }
                }
                '.msi' {
                    $msiCmd = "msiexec /a `"$PackagePath`" /qn TARGETDIR=`"$OutputPath`""
                    Start-Process -FilePath 'cmd.exe' -ArgumentList "/c $msiCmd" -Wait -NoNewWindow
                }
                default {
                    # Try generic extraction
                    Expand-Archive -Path $PackagePath -DestinationPath $OutputPath -Force -ErrorAction SilentlyContinue
                }
            }

            return [PSCustomObject]@{
                PackagePath = $PackagePath
                OutputPath  = $OutputPath
                Status      = 'Extracted'
            }
        }
        catch {
            Write-Warning "Failed to extract driver package: $_"
            return [PSCustomObject]@{
                PackagePath = $PackagePath
                OutputPath  = $OutputPath
                Status      = 'Failed'
                Error       = $_.Exception.Message
            }
        }
    }
}

function Get-SevenZipPath {
    <#
    .SYNOPSIS
        Gets the path to 7-Zip executable
    #>
    [CmdletBinding()]
    [OutputType([string])]
    param()

    $paths = @(
        (Get-Command -Name '7z' -ErrorAction SilentlyContinue).Source,
        (Get-Command -Name '7z.exe' -ErrorAction SilentlyContinue).Source,
        'C:\Program Files\7-Zip\7z.exe',
        'C:\Program Files (x86)\7-Zip\7z.exe'
    )

    foreach ($path in $paths) {
        if ($path -and (Test-Path -Path $path)) {
            return $path
        }
    }

    return $null
}
