#region CAB Creation Functions
function New-DriverCab {
    <#
    .SYNOPSIS
        Creates a CAB file containing drivers
    .DESCRIPTION
        Compresses drivers into a CAB file for efficient storage and deployment
    .PARAMETER SourcePath
        Directory containing drivers
    .PARAMETER OutputPath
        Directory for the output CAB file
    .PARAMETER CabName
        Name for the CAB file (default: Drivers_YYYYMMDD.cab)
    .PARAMETER CompressionLevel
        Compression level: None, MSZIP, LZX
    .EXAMPLE
        New-DriverCab -SourcePath 'C:\Drivers\Exported' -OutputPath 'C:\Drivers\CABs'
    #>
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Container })]
        [string]$SourcePath,

        [Parameter()]
        [string]$OutputPath,

        [Parameter()]
        [string]$CabName,

        [Parameter()]
        [ValidateSet('None', 'MSZIP', 'LZX')]
        [string]$CompressionLevel = 'LZX'
    )

    begin {
        Initialize-DriverManager

        if (-not $OutputPath) {
            $OutputPath = Join-Path -Path $script:DriversPath -ChildPath 'CABs'
        }

        if (-not (Test-Path -Path $OutputPath)) {
            New-Item -Path $OutputPath -ItemType Directory -Force | Out-Null
        }

        if (-not $CabName) {
            $CabName = "Drivers_$(Get-Date -Format 'yyyyMMdd').cab"
        }
    }

    process {
        try {
            $cabPath = Join-Path -Path $OutputPath -ChildPath $CabName

            Write-Host "  Creating driver CAB: $CabName" -ForegroundColor Cyan

            if ($PSCmdlet.ShouldProcess($cabPath, 'Create driver CAB')) {
                # Create DDF file for makecab
                $ddfPath = Join-Path -Path $env:TEMP -ChildPath 'drivers.ddf'
                $ddfContent = @"
.OPTION EXPLICIT
.Set CabinetNameTemplate=$CabName
.Set DiskDirectoryTemplate=$OutputPath
.Set Cabinet=on
.Set Compress=on
.Set CompressionType=$CompressionLevel
.Set MaxDiskSize=0
"@

                # Add all files
                $files = Get-ChildItem -Path $SourcePath -Recurse -File
                foreach ($file in $files) {
                    $relativePath = $file.FullName.Substring($SourcePath.Length + 1)
                    $ddfContent += "`n`"$($file.FullName)`" `"$relativePath`""
                }

                $ddfContent | Set-Content -Path $ddfPath -Encoding ASCII

                # Run makecab
                $makecabOutput = & makecab /F $ddfPath 2>&1

                # Cleanup
                Remove-Item -Path $ddfPath -Force -ErrorAction SilentlyContinue
                Remove-Item -Path (Join-Path -Path $OutputPath -ChildPath 'setup.inf') -Force -ErrorAction SilentlyContinue
                Remove-Item -Path (Join-Path -Path $OutputPath -ChildPath 'setup.rpt') -Force -ErrorAction SilentlyContinue

                if (Test-Path -Path $cabPath) {
                    $cabInfo = Get-Item -Path $cabPath
                    Write-Host "  ✓ Created: $CabName ($([math]::Round($cabInfo.Length / 1MB, 2)) MB)" -ForegroundColor Green

                    return [PSCustomObject]@{
                        CabPath         = $cabPath
                        Size            = $cabInfo.Length
                        FileCount       = $files.Count
                        Compression     = $CompressionLevel
                        Status          = 'Created'
                    }
                }
                else {
                    throw "CAB creation failed"
                }
            }
        }
        catch {
            Write-Error "Failed to create driver CAB: $_"
            return [PSCustomObject]@{
                CabPath = $cabPath
                Status  = 'Failed'
                Error   = $_.Exception.Message
            }
        }
    }
}

function Import-DriverCab {
    <#
    .SYNOPSIS
        Extracts a driver CAB file
    .PARAMETER CabPath
        Path to the CAB file
    .PARAMETER OutputPath
        Directory to extract to
    .EXAMPLE
        Import-DriverCab -CabPath 'C:\Drivers.cab' -OutputPath 'C:\Drivers\Staging'
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Leaf })]
        [string]$CabPath,

        [Parameter(Mandatory = $true)]
        [string]$OutputPath
    )

    process {
        try {
            if (-not (Test-Path -Path $OutputPath)) {
                New-Item -Path $OutputPath -ItemType Directory -Force | Out-Null
            }

            Write-Host "  Extracting CAB: $(Split-Path -Path $CabPath -Leaf)" -ForegroundColor Cyan

            $expandOutput = & expand.exe $CabPath -F:* $OutputPath 2>&1

            if ($LASTEXITCODE -eq 0) {
                $extractedFiles = Get-ChildItem -Path $OutputPath -Recurse -File
                Write-Host "  ✓ Extracted: $($extractedFiles.Count) files" -ForegroundColor Green

                return [PSCustomObject]@{
                    CabPath    = $CabPath
                    OutputPath = $OutputPath
                    FileCount  = $extractedFiles.Count
                    Status     = 'Extracted'
                }
            }
            else {
                throw "Expand failed: $expandOutput"
            }
        }
        catch {
            Write-Error "Failed to extract CAB: $_"
            return [PSCustomObject]@{
                CabPath = $CabPath
                Status  = 'Failed'
                Error   = $_.Exception.Message
            }
        }
    }
}
#endregion

#region WinPE Integration Functions
function Install-WinPEDrivers {
    <#
    .SYNOPSIS
        Injects drivers into a mounted WinPE image
    .DESCRIPTION
        Adds drivers to a mounted WinPE WIM for hardware support
    .PARAMETER MountPath
        Path where WinPE WIM is mounted
    .PARAMETER DriverPath
        Path to drivers (folder or CAB)
    .PARAMETER Recurse
        Search subfolders for drivers
    .EXAMPLE
        Install-WinPEDrivers -MountPath 'C:\WinPE\Mount' -DriverPath 'C:\Drivers'
    #>
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Container })]
        [string]$MountPath,

        [Parameter()]
        [string]$DriverPath,

        [Parameter()]
        [switch]$Recurse
    )

    begin {
        Initialize-DriverManager

        if (-not $DriverPath) {
            $DriverPath = Join-Path -Path $script:DriversPath -ChildPath 'Exported'
        }
    }

    process {
        try {
            Write-Host ''
            Write-Host '╔══════════════════════════════════════════════════════════════╗' -ForegroundColor Cyan
            Write-Host '║              DRIVER INJECTION PROCESS                         ║' -ForegroundColor Cyan
            Write-Host '╚══════════════════════════════════════════════════════════════╝' -ForegroundColor Cyan
            Write-Host ''

            $injectedCount = 0
            $failedCount = 0
            $injectedDrivers = [List[string]]::new()

            # Check if path is a CAB
            if ([Path]::GetExtension($DriverPath) -eq '.cab') {
                $stagingPath = Join-Path -Path $script:DriversPath -ChildPath 'Staging'
                Import-DriverCab -CabPath $DriverPath -OutputPath $stagingPath
                $DriverPath = $stagingPath
            }

            if (-not (Test-Path -Path $DriverPath)) {
                throw "Driver path not found: $DriverPath"
            }

            if ($PSCmdlet.ShouldProcess($MountPath, "Inject drivers from $DriverPath")) {
                Write-Host "  Injecting drivers into: $MountPath" -ForegroundColor Yellow

                # Use DISM to add drivers
                $dismArgs = @(
                    "/Image:`"$MountPath`""
                    '/Add-Driver'
                    "/Driver:`"$DriverPath`""
                )

                if ($Recurse) {
                    $dismArgs += '/Recurse'
                }

                $result = & dism.exe @dismArgs 2>&1

                # Parse results
                $successMatches = $result | Select-String -Pattern 'Successfully installed'
                $failMatches = $result | Select-String -Pattern 'failed'

                $injectedCount = $successMatches.Count
                $failedCount = $failMatches.Count

                # Get list of injected drivers
                $injectedList = Get-WindowsDriver -Path $MountPath | Where-Object { -not $_.Inbox }

                foreach ($drv in $injectedList) {
                    $injectedDrivers.Add($drv.OriginalFileName)
                }
            }

            Write-Host ''
            Write-Host "  Injection complete: $injectedCount drivers added" -ForegroundColor Green
            if ($failedCount -gt 0) {
                Write-Host "  Failures: $failedCount" -ForegroundColor Yellow
            }
            Write-Host ''

            return [PSCustomObject]@{
                MountPath      = $MountPath
                DriverSource   = $DriverPath
                InjectedCount  = $injectedCount
                FailedCount    = $failedCount
                Drivers        = $injectedDrivers
                Status         = if ($failedCount -eq 0) { 'Success' } else { 'Partial' }
            }
        }
        catch {
            Write-Error "Failed to inject drivers: $_"
            return [PSCustomObject]@{
                MountPath = $MountPath
                Status    = 'Failed'
                Error     = $_.Exception.Message
            }
        }
    }
}

function Copy-DriversToWinPE {
    <#
    .SYNOPSIS
        Copies drivers to WinPE for dynamic loading
    .DESCRIPTION
        Copies driver files to WinPE media for runtime loading with drvload
    .PARAMETER MountPath
        Path where WinPE WIM is mounted
    .PARAMETER DriverPath
        Path to drivers
    .PARAMETER DestinationPath
        Destination path in WinPE (default: X:\Drivers)
    .EXAMPLE
        Copy-DriversToWinPE -MountPath 'C:\WinPE\Mount' -DriverPath 'C:\Drivers'
    #>
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory = $true)]
        [string]$MountPath,

        [Parameter(Mandatory = $true)]
        [string]$DriverPath,

        [Parameter()]
        [string]$DestinationPath = 'Drivers'
    )

    process {
        try {
            $destFullPath = Join-Path -Path $MountPath -ChildPath $DestinationPath

            if ($PSCmdlet.ShouldProcess($destFullPath, 'Copy drivers')) {
                if (-not (Test-Path -Path $destFullPath)) {
                    New-Item -Path $destFullPath -ItemType Directory -Force | Out-Null
                }

                # Copy driver files
                Copy-Item -Path "$DriverPath\*" -Destination $destFullPath -Recurse -Force

                $copiedFiles = Get-ChildItem -Path $destFullPath -Filter '*.inf' -Recurse

                Write-Host "  ✓ Copied $($copiedFiles.Count) driver INF files to $DestinationPath" -ForegroundColor Green

                return [PSCustomObject]@{
                    SourcePath      = $DriverPath
                    DestinationPath = $destFullPath
                    DriverCount     = $copiedFiles.Count
                    Status          = 'Copied'
                }
            }
        }
        catch {
            Write-Error "Failed to copy drivers: $_"
            throw
        }
    }
}
