#region Hardware Detection Functions
function Get-HardwareInfo {
    <#
    .SYNOPSIS
        Gets hardware information for driver matching
    .DESCRIPTION
        Scans system hardware to identify required drivers
    .EXAMPLE
        Get-HardwareInfo
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject])]
    param()

    process {
        try {
            Write-Host "  Scanning hardware..." -ForegroundColor Cyan

            # Get system info
            $computerSystem = Get-CimInstance -ClassName Win32_ComputerSystem
            $baseBoard = Get-CimInstance -ClassName Win32_BaseBoard
            $processor = Get-CimInstance -ClassName Win32_Processor | Select-Object -First 1
            $videoController = Get-CimInstance -ClassName Win32_VideoController
            $networkAdapter = Get-CimInstance -ClassName Win32_NetworkAdapter | Where-Object { $_.PhysicalAdapter }
            $diskDrive = Get-CimInstance -ClassName Win32_DiskDrive

            $hardware = [PSCustomObject]@{
                ComputerName  = $computerSystem.Name
                Manufacturer  = $computerSystem.Manufacturer
                Model         = $computerSystem.Model

                Motherboard   = [PSCustomObject]@{
                    Manufacturer = $baseBoard.Manufacturer
                    Product      = $baseBoard.Product
                    SerialNumber = $baseBoard.SerialNumber
                }

                Processor     = [PSCustomObject]@{
                    Name         = $processor.Name
                    Manufacturer = $processor.Manufacturer
                    Cores        = $processor.NumberOfCores
                    Threads      = $processor.NumberOfLogicalProcessors
                }

                Graphics      = @($videoController | ForEach-Object {
                    [PSCustomObject]@{
                        Name           = $_.Name
                        AdapterRAM     = [math]::Round($_.AdapterRAM / 1GB, 2)
                        DriverVersion  = $_.DriverVersion
                        PNPDeviceID    = $_.PNPDeviceID
                    }
                })

                Network       = @($networkAdapter | ForEach-Object {
                    [PSCustomObject]@{
                        Name        = $_.Name
                        Manufacturer = $_.Manufacturer
                        MACAddress  = $_.MACAddress
                        PNPDeviceID = $_.PNPDeviceID
                    }
                })

                Storage       = @($diskDrive | ForEach-Object {
                    [PSCustomObject]@{
                        Model       = $_.Model
                        Size        = [math]::Round($_.Size / 1GB, 2)
                        MediaType   = $_.MediaType
                        Interface   = $_.InterfaceType
                        PNPDeviceID = $_.PNPDeviceID
                    }
                })
            }

            return $hardware
        }
        catch {
            Write-Error "Failed to get hardware info: $_"
            throw
        }
    }
}

function Test-DriverCompatibility {
    <#
    .SYNOPSIS
        Tests if drivers are compatible with detected hardware
    .PARAMETER DriverPath
        Path to driver folder
    .EXAMPLE
        Test-DriverCompatibility -DriverPath 'C:\Drivers'
    #>
    [CmdletBinding()]
    [OutputType([PSCustomObject[]])]
    param(
        [Parameter(Mandatory = $true)]
        [ValidateScript({ Test-Path -Path $_ -PathType Container })]
        [string]$DriverPath
    )

    process {
        try {
            $results = [List[PSCustomObject]]::new()
            $hardware = Get-HardwareInfo

            # Get all hardware IDs
            $pnpDevices = Get-PnpDevice | Where-Object { $_.Status -eq 'OK' }
            $hardwareIds = $pnpDevices | ForEach-Object {
                (Get-PnpDeviceProperty -InstanceId $_.InstanceId -KeyName 'DEVPKEY_Device_HardwareIds' -ErrorAction SilentlyContinue).Data
            } | Where-Object { $_ }

            # Scan driver INFs
            $infFiles = Get-ChildItem -Path $DriverPath -Filter '*.inf' -Recurse

            foreach ($inf in $infFiles) {
                $infContent = Get-Content -Path $inf.FullName -Raw

                # Extract hardware IDs from INF
                $hwIdMatches = $infContent | Select-String -Pattern 'PCI\\VEN_[0-9A-F]+&DEV_[0-9A-F]+' -AllMatches
                $infHwIds = $hwIdMatches.Matches.Value | Select-Object -Unique

                $matchFound = $false
                foreach ($hwId in $infHwIds) {
                    if ($hardwareIds -contains $hwId) {
                        $matchFound = $true
                        break
                    }
                }

                $results.Add([PSCustomObject]@{
                    DriverInf    = $inf.Name
                    Path         = $inf.FullName
                    Compatible   = $matchFound
                    HardwareIds  = $infHwIds
                })
            }

            return $results
        }
        catch {
            Write-Error "Failed to test driver compatibility: $_"
            throw
        }
    }
}
#endregion

