#region Driver Removal Functions
function Remove-ThirdPartyDrivers {
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([DriverRemovalResult])]
    param(
        [Parameter()]
        [string[]]$ExcludeClasses = @('Keyboard', 'Mouse'),

        [Parameter()]
        [string[]]$ExcludeProviders = @('Microsoft'),

        [Parameter()]
        [switch]$Force
    )

    $result = [DriverRemovalResult]::new()
    $result.RemovedDrivers = @()
    $result.FailedDrivers = @()

    try {
        Write-Log -Message "Starting third-party driver removal" -Level Information

        # Get all third-party drivers
        $drivers = Get-WindowsDriver -Online -ErrorAction Stop | Where-Object {
            $_.OriginalFileName -notlike '*Microsoft*' -and
            $_.ClassName -notin $ExcludeClasses -and
            $_.ProviderName -notin $ExcludeProviders -and
            -not $_.Inbox
        }

        if ($drivers.Count -eq 0) {
            Write-Log -Message "No third-party drivers found to remove" -Level Information
            $result.Success = $true
            return $result
        }

        Write-Log -Message "Found $($drivers.Count) third-party drivers to remove" -Level Information

        foreach ($driver in $drivers) {
            $driverName = $driver.Driver

            if ($PSCmdlet.ShouldProcess($driverName, "Remove driver")) {
                try {
                    # Use pnputil to remove the driver
                    $pnpResult = & pnputil /delete-driver $driverName /force 2>&1

                    if ($LASTEXITCODE -eq 0) {
                        Write-Log -Message "Removed driver: $driverName ($($driver.ProviderName))" -Level Verbose
                        $result.RemovedDrivers += $driverName
                        $result.DriversRemoved++
                    }
                    else {
                        Write-Log -Message "Failed to remove driver: $driverName - $pnpResult" -Level Warning
                        $result.FailedDrivers += $driverName
                        $result.DriversFailed++
                    }
                }
                catch {
                    Write-Log -Message "Error removing driver $driverName : $_" -Level Warning
                    $result.FailedDrivers += $driverName
                    $result.DriversFailed++
                }
            }
        }

        $result.Success = $result.DriversFailed -eq 0
        Write-Log -Message "Driver removal complete. Removed: $($result.DriversRemoved), Failed: $($result.DriversFailed)" -Level Information
    }
    catch {
        Write-Log -Message "Driver removal failed: $_" -Level Error
        $result.Success = $false
        $result.ErrorMessage = $_.Exception.Message
    }

    return $result
}

function Get-InstalledDrivers {
    [CmdletBinding()]
    [OutputType([PSCustomObject[]])]
    param(
        [Parameter()]
        [switch]$ThirdPartyOnly,

        [Parameter()]
        [string[]]$ClassFilter
    )

    try {
        $drivers = Get-WindowsDriver -Online -ErrorAction Stop

        if ($ThirdPartyOnly) {
            $drivers = $drivers | Where-Object { -not $_.Inbox }
        }

        if ($ClassFilter -and $ClassFilter.Count -gt 0) {
            $drivers = $drivers | Where-Object { $_.ClassName -in $ClassFilter }
        }

        return $drivers | Select-Object @{N='DriverName';E={$_.Driver}},
                                         @{N='OriginalName';E={$_.OriginalFileName}},
                                         @{N='ClassName';E={$_.ClassName}},
                                         @{N='Provider';E={$_.ProviderName}},
                                         @{N='Version';E={$_.Version}},
                                         @{N='Date';E={$_.Date}},
                                         @{N='IsInbox';E={$_.Inbox}}
    }
    catch {
        Write-Log -Message "Failed to enumerate drivers: $_" -Level Error
        return @()
    }
}
#endregion

#region Pre/Post Script Functions
function Invoke-CaptureScript {
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([CapturePhase])]
    param(
        [Parameter(Mandatory)]
        [string]$ScriptPath,

        [Parameter()]
        [string]$PhaseName = 'CustomScript',

        [Parameter()]
        [hashtable]$Parameters,

        [Parameter()]
        [int]$TimeoutSeconds = 300
    )

    $phase = [CapturePhase]::new($PhaseName)

    try {
        if (-not (Test-Path -Path $ScriptPath)) {
            $phase.Complete($false, "Script not found: $ScriptPath", 1)
            return $phase
        }

        Write-Log -Message "Executing script: $ScriptPath" -Level Information

        if ($PSCmdlet.ShouldProcess($ScriptPath, "Execute script")) {
            $scriptBlock = {
                param($Path, $Params)
                if ($Params) {
                    & $Path @Params
                }
                else {
                    & $Path
                }
            }

            $job = Start-Job -ScriptBlock $scriptBlock -ArgumentList $ScriptPath, $Parameters
            $completed = Wait-Job -Job $job -Timeout $TimeoutSeconds

            if ($completed) {
                $output = Receive-Job -Job $job
                $jobState = $job.State
                Remove-Job -Job $job -Force

                if ($jobState -eq 'Completed') {
                    Write-Log -Message "Script completed successfully" -Level Information
                    $phase.Complete($true, "Script completed: $output", 0)
                }
                else {
                    Write-Log -Message "Script failed: $output" -Level Error
                    $phase.Complete($false, "Script failed: $output", 1)
                }
            }
            else {
                Stop-Job -Job $job
                Remove-Job -Job $job -Force
                Write-Log -Message "Script timed out after $TimeoutSeconds seconds" -Level Error
                $phase.Complete($false, "Script timed out", -1)
            }
        }
        else {
            $phase.Complete($true, "Script execution skipped (WhatIf)", 0)
        }
    }
    catch {
        Write-Log -Message "Script execution failed: $_" -Level Error
        $phase.Complete($false, "Script execution failed: $_", -1)
    }

    return $phase
}

function Invoke-PreCaptureScripts {
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([CapturePhase[]])]
    param(
        [Parameter(Mandatory)]
        [string[]]$ScriptPaths
    )

    $phases = @()
    $index = 1

    foreach ($scriptPath in $ScriptPaths) {
        $phase = Invoke-CaptureScript -ScriptPath $scriptPath -PhaseName "PreCapture_$index"
        $phases += $phase

        if (-not $phase.Success) {
            Write-Log -Message "Pre-capture script failed: $scriptPath" -Level Warning
        }

        $index++
    }

    return $phases
}

function Invoke-PostCaptureScripts {
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([CapturePhase[]])]
    param(
        [Parameter(Mandatory)]
        [string[]]$ScriptPaths
    )

    $phases = @()
    $index = 1

    foreach ($scriptPath in $ScriptPaths) {
        $phase = Invoke-CaptureScript -ScriptPath $scriptPath -PhaseName "PostCapture_$index"
        $phases += $phase

        if (-not $phase.Success) {
            Write-Log -Message "Post-capture script failed: $scriptPath" -Level Warning
        }

        $index++
    }

    return $phases
}
