#region Image Capture Functions
function Start-ImageCapture {
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([CaptureResult])]
    param(
        [Parameter(Mandatory)]
        [CaptureConfiguration]$Configuration
    )

    $result = [CaptureResult]::new()
    $result.StartTime = Get-Date
    $result.Format = $Configuration.Format

    try {
        # Validate configuration
        $validationPhase = Test-CaptureConfiguration -Configuration $Configuration
        $result.Phases += $validationPhase

        if (-not $validationPhase.Success) {
            $result.ErrorMessage = $validationPhase.Message
            return $result
        }

        # Run pre-capture scripts
        if ($Configuration.PreCaptureScripts.Count -gt 0) {
            $preScriptPhases = Invoke-PreCaptureScripts -ScriptPaths $Configuration.PreCaptureScripts
            $result.Phases += $preScriptPhases
        }

        # Remove drivers if requested
        if ($Configuration.RemoveDrivers) {
            $driverPhase = [CapturePhase]::new('DriverRemoval')
            $driverResult = Remove-ThirdPartyDrivers
            $driverPhase.Complete($driverResult.Success, 
                "Removed $($driverResult.DriversRemoved) drivers", 
                ($driverResult.Success ? 0 : 1))
            $result.Phases += $driverPhase
        }

        # Run Sysprep if requested
        if ($Configuration.RunSysprep) {
            $sysprepPhase = Start-SysprepOperation `
                -Mode $Configuration.SysprepMode `
                -Generalize:$Configuration.Generalize `
                -AnswerFile $Configuration.AnswerFilePath `
                -Quit

            $result.Phases += $sysprepPhase

            if (-not $sysprepPhase.Success) {
                $result.ErrorMessage = "Sysprep failed: $($sysprepPhase.Message)"
                return $result
            }
        }

        # Perform capture based on format
        $capturePhase = switch ($Configuration.Format) {
            'WIM' { 
                Invoke-WimCapture -Configuration $Configuration 
            }
            'ESD' { 
                Invoke-EsdCapture -Configuration $Configuration 
            }
            'FFU' { 
                Invoke-FfuCapture -Configuration $Configuration 
            }
            'SplitWIM' { 
                $splitResult = Invoke-SplitWimCapture -Configuration $Configuration
                $result.SplitFiles = $splitResult.SplitFiles
                $splitResult.Phase
            }
        }

        $result.Phases += $capturePhase

        if ($capturePhase.Success) {
            $result.ImagePath = $Configuration.DestinationPath

            # Verify capture if requested
            if ($Configuration.VerifyCapture) {
                $verifyPhase = Test-CapturedImage -ImagePath $result.ImagePath
                $result.Phases += $verifyPhase
            }

            # Calculate hash and size
            if (Test-Path -Path $result.ImagePath) {
                $fileInfo = Get-Item -Path $result.ImagePath
                $result.ImageSizeBytes = $fileInfo.Length
                $result.ImageHash = (Get-FileHash -Path $result.ImagePath -Algorithm SHA256).Hash
            }

            # Run post-capture scripts
            if ($Configuration.PostCaptureScripts.Count -gt 0) {
                $postScriptPhases = Invoke-PostCaptureScripts -ScriptPaths $Configuration.PostCaptureScripts
                $result.Phases += $postScriptPhases
            }

            $result.Success = $true
        }
        else {
            $result.ErrorMessage = $capturePhase.Message
        }
    }
    catch {
        Write-Log -Message "Image capture failed: $_" -Level Error
        $result.ErrorMessage = $_.Exception.Message
    }
    finally {
        $result.EndTime = Get-Date
        $result.Duration = $result.EndTime - $result.StartTime
    }

    return $result
}

function Invoke-WimCapture {
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([CapturePhase])]
    param(
        [Parameter(Mandatory)]
        [CaptureConfiguration]$Configuration
    )

    $phase = [CapturePhase]::new('WimCapture')

    try {
        $sourceVolume = $Configuration.SourceVolume
        $destination = $Configuration.DestinationPath
        $imageName = $Configuration.ImageName
        $description = $Configuration.ImageDescription

        # Build DISM arguments
        $compressionArg = switch ($Configuration.Compression) {
            'None' { 'none' }
            'Fast' { 'fast' }
            'Maximum' { 'max' }
        }

        Write-Log -Message "Starting WIM capture: $sourceVolume -> $destination" -Level Information

        if ($PSCmdlet.ShouldProcess("$sourceVolume", "Capture to WIM")) {
            # Ensure destination directory exists
            $destDir = Split-Path -Path $destination -Parent
            if (-not (Test-Path -Path $destDir)) {
                New-Item -Path $destDir -ItemType Directory -Force | Out-Null
            }

            $arguments = @(
                '/Capture-Image'
                "/ImageFile:`"$destination`""
                "/CaptureDir:`"$sourceVolume`""
                "/Name:`"$imageName`""
                "/Compress:$compressionArg"
            )

            if ($description) {
                $arguments += "/Description:`"$description`""
            }

            $argumentString = $arguments -join ' '
            Write-Log -Message "DISM command: $argumentString" -Level Verbose

            $process = Start-Process -FilePath $script:DismPath `
                                      -ArgumentList $argumentString `
                                      -Wait `
                                      -PassThru `
                                      -NoNewWindow `
                                      -RedirectStandardOutput (Join-Path $script:CaptureWorkDir 'dism_capture.log') `
                                      -RedirectStandardError (Join-Path $script:CaptureWorkDir 'dism_capture_err.log')

            if ($process.ExitCode -eq 0) {
                Write-Log -Message "WIM capture completed successfully" -Level Information
                $phase.Complete($true, "WIM capture completed", 0)
            }
            else {
                $errorLog = Get-Content -Path (Join-Path $script:CaptureWorkDir 'dism_capture_err.log') -Raw -ErrorAction SilentlyContinue
                Write-Log -Message "WIM capture failed with exit code: $($process.ExitCode)" -Level Error
                $phase.Complete($false, "WIM capture failed: $errorLog", $process.ExitCode)
            }
        }
        else {
            $phase.Complete($true, "WIM capture skipped (WhatIf)", 0)
        }
    }
    catch {
        Write-Log -Message "WIM capture error: $_" -Level Error
        $phase.Complete($false, "WIM capture error: $_", -1)
    }

    return $phase
}

function Invoke-EsdCapture {
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([CapturePhase])]
    param(
        [Parameter(Mandatory)]
        [CaptureConfiguration]$Configuration
    )

    $phase = [CapturePhase]::new('EsdCapture')

    try {
        # First capture as WIM, then convert to ESD
        $tempWimPath = Join-Path -Path $script:CaptureWorkDir -ChildPath "temp_$(Get-Date -Format 'yyyyMMddHHmmss').wim"

        $tempConfig = [CaptureConfiguration]::new()
        $tempConfig.SourceVolume = $Configuration.SourceVolume
        $tempConfig.DestinationPath = $tempWimPath
        $tempConfig.ImageName = $Configuration.ImageName
        $tempConfig.ImageDescription = $Configuration.ImageDescription
        $tempConfig.Compression = [CompressionType]::Maximum

        Write-Log -Message "Capturing WIM for ESD conversion" -Level Information

        $wimPhase = Invoke-WimCapture -Configuration $tempConfig

        if (-not $wimPhase.Success) {
            $phase.Complete($false, "WIM capture for ESD failed: $($wimPhase.Message)", $wimPhase.ExitCode)
            return $phase
        }

        # Convert WIM to ESD
        Write-Log -Message "Converting WIM to ESD" -Level Information

        if ($PSCmdlet.ShouldProcess($tempWimPath, "Convert to ESD")) {
            $destination = $Configuration.DestinationPath
            $destDir = Split-Path -Path $destination -Parent
            if (-not (Test-Path -Path $destDir)) {
                New-Item -Path $destDir -ItemType Directory -Force | Out-Null
            }

            $arguments = @(
                '/Export-Image'
                "/SourceImageFile:`"$tempWimPath`""
                '/SourceIndex:1'
                "/DestinationImageFile:`"$destination`""
                '/Compress:recovery'
            )

            $argumentString = $arguments -join ' '

            $process = Start-Process -FilePath $script:DismPath `
                                      -ArgumentList $argumentString `
                                      -Wait `
                                      -PassThru `
                                      -NoNewWindow

            # Cleanup temp WIM
            if (Test-Path -Path $tempWimPath) {
                Remove-Item -Path $tempWimPath -Force -ErrorAction SilentlyContinue
            }

            if ($process.ExitCode -eq 0) {
                Write-Log -Message "ESD capture completed successfully" -Level Information
                $phase.Complete($true, "ESD capture completed", 0)
            }
            else {
                Write-Log -Message "ESD conversion failed with exit code: $($process.ExitCode)" -Level Error
                $phase.Complete($false, "ESD conversion failed", $process.ExitCode)
            }
        }
        else {
            $phase.Complete($true, "ESD capture skipped (WhatIf)", 0)
        }
    }
    catch {
        Write-Log -Message "ESD capture error: $_" -Level Error
        $phase.Complete($false, "ESD capture error: $_", -1)
    }

    return $phase
}

function Invoke-FfuCapture {
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([CapturePhase])]
    param(
        [Parameter(Mandatory)]
        [CaptureConfiguration]$Configuration
    )

    $phase = [CapturePhase]::new('FfuCapture')

    try {
        $sourceVolume = $Configuration.SourceVolume
        $destination = $Configuration.DestinationPath
        $imageName = $Configuration.ImageName
        $description = $Configuration.ImageDescription

        # Get physical disk number from volume
        $volume = Get-Volume -DriveLetter ($sourceVolume.TrimEnd(':\')) -ErrorAction SilentlyContinue
        if (-not $volume) {
            $phase.Complete($false, "Could not find volume: $sourceVolume", 1)
            return $phase
        }

        $partition = $volume | Get-Partition -ErrorAction SilentlyContinue
        if (-not $partition) {
            $phase.Complete($false, "Could not find partition for volume: $sourceVolume", 1)
            return $phase
        }

        $diskNumber = $partition.DiskNumber
        $physicalDisk = "\\.\PhysicalDrive$diskNumber"

        Write-Log -Message "Starting FFU capture: Disk $diskNumber -> $destination" -Level Information

        if ($PSCmdlet.ShouldProcess($physicalDisk, "Capture to FFU")) {
            $destDir = Split-Path -Path $destination -Parent
            if (-not (Test-Path -Path $destDir)) {
                New-Item -Path $destDir -ItemType Directory -Force | Out-Null
            }

            $compressionArg = switch ($Configuration.Compression) {
                'None' { 'none' }
                'Fast' { 'default' }
                'Maximum' { 'default' }
            }

            $arguments = @(
                '/Capture-FFU'
                "/ImageFile:`"$destination`""
                "/CaptureDrive:$physicalDisk"
                "/Name:`"$imageName`""
                "/Compress:$compressionArg"
            )

            if ($description) {
                $arguments += "/Description:`"$description`""
            }

            $argumentString = $arguments -join ' '
            Write-Log -Message "DISM FFU command: $argumentString" -Level Verbose

            $process = Start-Process -FilePath $script:DismPath `
                                      -ArgumentList $argumentString `
                                      -Wait `
                                      -PassThru `
                                      -NoNewWindow

            if ($process.ExitCode -eq 0) {
                Write-Log -Message "FFU capture completed successfully" -Level Information
                $phase.Complete($true, "FFU capture completed", 0)
            }
            else {
                Write-Log -Message "FFU capture failed with exit code: $($process.ExitCode)" -Level Error
                $phase.Complete($false, "FFU capture failed", $process.ExitCode)
            }
        }
        else {
            $phase.Complete($true, "FFU capture skipped (WhatIf)", 0)
        }
    }
    catch {
        Write-Log -Message "FFU capture error: $_" -Level Error
        $phase.Complete($false, "FFU capture error: $_", -1)
    }

    return $phase
}

function Invoke-SplitWimCapture {
    [CmdletBinding(SupportsShouldProcess)]
    [OutputType([PSCustomObject])]
    param(
        [Parameter(Mandatory)]
        [CaptureConfiguration]$Configuration
    )

    $result = [PSCustomObject]@{
        Phase = [CapturePhase]::new('SplitWimCapture')
        SplitFiles = @()
    }

    try {
        # First capture as standard WIM
        $tempWimPath = Join-Path -Path $script:CaptureWorkDir -ChildPath "temp_$(Get-Date -Format 'yyyyMMddHHmmss').wim"

        $tempConfig = [CaptureConfiguration]::new()
        $tempConfig.SourceVolume = $Configuration.SourceVolume
        $tempConfig.DestinationPath = $tempWimPath
        $tempConfig.ImageName = $Configuration.ImageName
        $tempConfig.ImageDescription = $Configuration.ImageDescription
        $tempConfig.Compression = $Configuration.Compression

        Write-Log -Message "Capturing WIM for splitting" -Level Information

        $wimPhase = Invoke-WimCapture -Configuration $tempConfig

        if (-not $wimPhase.Success) {
            $result.Phase.Complete($false, "WIM capture for split failed: $($wimPhase.Message)", $wimPhase.ExitCode)
            return $result
        }

        # Split the WIM
        $splitSizeMB = $Configuration.SplitSizeMB
        $destination = $Configuration.DestinationPath

        Write-Log -Message "Splitting WIM into ${splitSizeMB}MB chunks" -Level Information

        if ($PSCmdlet.ShouldProcess($tempWimPath, "Split WIM")) {
            $destDir = Split-Path -Path $destination -Parent
            if (-not (Test-Path -Path $destDir)) {
                New-Item -Path $destDir -ItemType Directory -Force | Out-Null
            }

            $arguments = @(
                '/Split-Image'
                "/ImageFile:`"$tempWimPath`""
                "/SWMFile:`"$destination`""
                "/FileSize:$splitSizeMB"
            )

            $argumentString = $arguments -join ' '

            $process = Start-Process -FilePath $script:DismPath `
                                      -ArgumentList $argumentString `
                                      -Wait `
                                      -PassThru `
                                      -NoNewWindow

            # Cleanup temp WIM
            if (Test-Path -Path $tempWimPath) {
                Remove-Item -Path $tempWimPath -Force -ErrorAction SilentlyContinue
            }

            if ($process.ExitCode -eq 0) {
                # Find all split files
                $baseName = [System.IO.Path]::GetFileNameWithoutExtension($destination)
                $baseDir = Split-Path -Path $destination -Parent
                $result.SplitFiles = Get-ChildItem -Path $baseDir -Filter "$baseName*.swm" | 
                    Select-Object -ExpandProperty FullName | 
                    Sort-Object

                Write-Log -Message "Split WIM capture completed. Created $($result.SplitFiles.Count) files" -Level Information
                $result.Phase.Complete($true, "Split WIM capture completed", 0)
            }
            else {
                Write-Log -Message "Split WIM failed with exit code: $($process.ExitCode)" -Level Error
                $result.Phase.Complete($false, "Split WIM failed", $process.ExitCode)
            }
        }
        else {
            $result.Phase.Complete($true, "Split WIM capture skipped (WhatIf)", 0)
        }
    }
    catch {
        Write-Log -Message "Split WIM capture error: $_" -Level Error
        $result.Phase.Complete($false, "Split WIM capture error: $_", -1)
    }

    return $result
}

function Test-CaptureConfiguration {
    [CmdletBinding()]
    [OutputType([CapturePhase])]
    param(
        [Parameter(Mandatory)]
        [CaptureConfiguration]$Configuration
    )

    $phase = [CapturePhase]::new('ConfigurationValidation')
    $errors = @()

    try {
        # Validate source volume
        if ([string]::IsNullOrEmpty($Configuration.SourceVolume)) {
            $errors += "Source volume is required"
        }
        elseif (-not (Test-Path -Path $Configuration.SourceVolume)) {
            $errors += "Source volume not found: $($Configuration.SourceVolume)"
        }

        # Validate destination path
        if ([string]::IsNullOrEmpty($Configuration.DestinationPath)) {
            $errors += "Destination path is required"
        }
        else {
            $destDir = Split-Path -Path $Configuration.DestinationPath -Parent
            if ($destDir -and -not (Test-Path -Path $destDir)) {
                # Try to create directory
                try {
                    New-Item -Path $destDir -ItemType Directory -Force | Out-Null
                }
                catch {
                    $errors += "Cannot create destination directory: $destDir"
                }
            }
        }

        # Validate image name
        if ([string]::IsNullOrEmpty($Configuration.ImageName)) {
            $errors += "Image name is required"
        }

        # Validate answer file if specified
        if ($Configuration.AnswerFilePath -and -not (Test-Path -Path $Configuration.AnswerFilePath)) {
            $errors += "Answer file not found: $($Configuration.AnswerFilePath)"
        }

        # Validate pre-capture scripts
        foreach ($script in $Configuration.PreCaptureScripts) {
            if (-not (Test-Path -Path $script)) {
                $errors += "Pre-capture script not found: $script"
            }
        }

        # Validate post-capture scripts
        foreach ($script in $Configuration.PostCaptureScripts) {
            if (-not (Test-Path -Path $script)) {
                $errors += "Post-capture script not found: $script"
            }
        }

        # Check DISM availability
        if (-not (Test-Path -Path $script:DismPath)) {
            $errors += "DISM not found at: $($script:DismPath)"
        }

        # Check Sysprep if needed
        if ($Configuration.RunSysprep -and -not (Test-SysprepAvailability)) {
            $errors += "Sysprep is not available"
        }

        if ($errors.Count -gt 0) {
            $errorMessage = $errors -join '; '
            Write-Log -Message "Configuration validation failed: $errorMessage" -Level Error
            $phase.Complete($false, $errorMessage, 1)
        }
        else {
            Write-Log -Message "Configuration validation passed" -Level Information
            $phase.Complete($true, "Configuration valid", 0)
        }
    }
    catch {
        Write-Log -Message "Configuration validation error: $_" -Level Error
        $phase.Complete($false, "Validation error: $_", -1)
    }

    return $phase
}

function Test-CapturedImage {
    [CmdletBinding()]
    [OutputType([CapturePhase])]
    param(
        [Parameter(Mandatory)]
        [string]$ImagePath
    )

    $phase = [CapturePhase]::new('ImageVerification')

    try {
        if (-not (Test-Path -Path $ImagePath)) {
            $phase.Complete($false, "Image file not found: $ImagePath", 1)
            return $phase
        }

        Write-Log -Message "Verifying captured image: $ImagePath" -Level Information

        # Get image info using DISM
        $arguments = "/Get-ImageInfo /ImageFile:`"$ImagePath`""

        $result = & $script:DismPath $arguments.Split(' ') 2>&1

        if ($LASTEXITCODE -eq 0) {
            # Parse image info
            $imageInfo = $result | Out-String

            if ($imageInfo -match 'Index\s*:\s*(\d+)') {
                $indexCount = ($imageInfo | Select-String -Pattern 'Index\s*:\s*\d+' -AllMatches).Matches.Count
                Write-Log -Message "Image verified. Contains $indexCount index(es)" -Level Information
                $phase.Complete($true, "Image verified with $indexCount index(es)", 0)
            }
            else {
                Write-Log -Message "Image verification completed but no indexes found" -Level Warning
                $phase.Complete($true, "Image verified (no indexes parsed)", 0)
            }
        }
        else {
            Write-Log -Message "Image verification failed" -Level Error
            $phase.Complete($false, "Image verification failed: $result", $LASTEXITCODE)
        }
    }
    catch {
        Write-Log -Message "Image verification error: $_" -Level Error
        $phase.Complete($false, "Verification error: $_", -1)
    }

    return $phase
}
