$DevRoot = 'C:\Users\C-Man\OneDrive\Dev'
$LogRoot = 'C:\Users\C-Man\Documents\CleanupLogs\20260205-191954'
$AllDirs = Get-ChildItem -Path $DevRoot -Directory -ErrorAction SilentlyContinue

# System junctions to never touch
$SystemExclusions = @('diagnostics') # already handled in Phase 1

$RemovalPlan = @()

foreach ($dir in $AllDirs) {
    $name = $dir.Name
    $originalName = $null

    # Skip diagnostics (already handled)
    if ($name -match '^diagnostics(_\d+)?$') { continue }

    # Pattern 1: "Name_N" (e.g., PSColor_1)
    if ($name -match '^(.+?)_(\d+)$') {
        $candidate = $Matches[1]
        # Verify it's not a versioned name like "v1" that happens to end with _N
        $originalName = $candidate
    }
    # Pattern 2: "Name_N.Ext" (e.g., Aurora_1.Core -> Aurora.Core)
    elseif ($name -match '^(.+?)_(\d+)\.(.+)$') {
        $originalName = "$($Matches[1]).$($Matches[3])"
    }
    # Pattern 3: "Name N" with space-number (e.g., "Better11-Unified-Suite-Complete 2")
    elseif ($name -match '^(.+?)\s+(\d+)$') {
        $originalName = $Matches[1]
    }
    # Pattern 4: "Name N_N" (e.g., "Better11-Unified-Suite-Complete 2_1")
    elseif ($name -match '^(.+?)\s+(\d+)_(\d+)$') {
        $originalName = $Matches[1]
    }

    if ($originalName) {
        $originalPath = Join-Path $DevRoot $originalName
        $origExists = Test-Path $originalPath

        $dupeItemCount = 0
        try {
            $dupeItemCount = (Get-ChildItem $dir.FullName -Recurse -File -ErrorAction SilentlyContinue | Measure-Object).Count
        } catch {}

        $RemovalPlan += [PSCustomObject]@{
            Duplicate    = $dir.Name
            DupePath     = $dir.FullName
            Original     = $originalName
            OrigPath     = $originalPath
            OrigExists   = $origExists
            DupeItems    = $dupeItemCount
        }
    }
}

# Separate safe vs needs-review
$SafeToRemove = $RemovalPlan | Where-Object { $_.OrigExists -eq $true }
$NeedsReview = $RemovalPlan | Where-Object { $_.OrigExists -eq $false }

# Export full manifest
$RemovalPlan | Export-Csv "$LogRoot\phase2-full-manifest.csv" -NoTypeInformation

Write-Host "=== PHASE 2: DUPLICATE DIRECTORIES ==="
Write-Host "Total candidates: $($RemovalPlan.Count)"
Write-Host "Safe to remove (original exists): $($SafeToRemove.Count)"
Write-Host "Needs review (no original): $($NeedsReview.Count)"

Write-Host "`n--- SAFE TO REMOVE ---"
$SafeToRemove | ForEach-Object {
    Write-Host "  DELETE: $($_.Duplicate) -> original: $($_.Original) (items: $($_.DupeItems))"
}

Write-Host "`n--- NEEDS REVIEW ---"
$NeedsReview | ForEach-Object {
    Write-Host "  REVIEW: $($_.Duplicate) -> expected: $($_.Original) (items: $($_.DupeItems))"
}

# Execute safe removals
Write-Host "`n--- EXECUTING SAFE REMOVALS ---"
$deleted = 0
$errors = 0
foreach ($item in $SafeToRemove) {
    try {
        Remove-Item -Path $item.DupePath -Recurse -Force -ErrorAction Stop
        $deleted++
    } catch {
        Write-Host "  ERROR removing $($item.Duplicate): $($_.Exception.Message)"
        $errors++
    }
}

Write-Host "`nPhase 2 complete: Deleted $deleted directories, $errors errors, $($NeedsReview.Count) skipped for review"
Write-Host '---DONE---'
